{
  "name": "Linha Viva Itabaiana",
  "description": "Sistema de controle de estoque e solicitação de materiais para frotas de linha viva, com painel administrativo e exportação de dados.",
  "requestFramePermissions": []
}

export interface InventoryItem {
  id: string;
  name: string;
  balance: number;
}

export interface RequestedItem {
  itemId: string;
  itemName: string;
  quantity: number;
}

export interface MaterialRequest {
  id: string;
  vtr: string;
  items: RequestedItem[];
  status: 'pending' | 'served';
  timestamp: number;
  requesterName: string;
}

export interface Transaction {
  id: string;
  itemId: string;
  type: 'in' | 'out';
  quantity: number;
  timestamp: number;
  description: string;
}

export const COLORS = {
  primary: '#003366', // Blue
  secondary: '#FF8C00', // Orange
  accent: '#FFFFFF', // White
};

// Unique vehicle list from prompt
export const VEHICLES = [
  "1645", "1700", "1711", "1769", "1770", "1811", "1859", 
  "1847", "1845", "4001", "4006", "4013", "4014", 
  "4015", "4016", "4020", "4025"
].sort((a, b) => Number(a) - Number(b));

export const ADMIN_PASSWORD = "Dsa21";

export const INITIAL_INVENTORY = [
  { id: '1', name: 'Luva Isolante Classe 2', balance: 10 },
  { id: '2', name: 'Bastão de Manobra', balance: 5 },
  { id: '3', name: 'Cobertura de Linha Viva', balance: 15 },
  { id: '4', name: 'Manta Isolante', balance: 8 },
  { id: '5', name: 'Esticador de Corrente', balance: 4 },
];

import React from 'react';

export const BucketTruckIcon = ({ className = "w-12 h-12" }: { className?: string }) => (
  <svg 
    viewBox="0 0 100 100" 
    className={className}
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
  >
    {/* Truck body */}
    <rect x="15" y="60" width="55" height="20" rx="2" fill="currentColor" />
    <rect x="70" y="65" width="20" height="15" rx="2" fill="currentColor" />
    {/* Wheels */}
    <circle cx="25" cy="82" r="6" fill="#111" />
    <circle cx="55" cy="82" r="6" fill="#111" />
    <circle cx="82" cy="82" r="6" fill="#111" />
    {/* The Boom / Cesto mechanism */}
    <path d="M40 60 L40 30" stroke="#FF8C00" strokeWidth="4" />
    <path d="M40 30 L65 20" stroke="#FF8C00" strokeWidth="3" />
    {/* The Bucket */}
    <rect x="65" y="10" width="15" height="12" rx="1" fill="#FFFFFF" stroke="#FF8C00" strokeWidth="2" />
  </svg>
);

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import { BucketTruckIcon } from './components/Icons';
import { INITIAL_INVENTORY } from './constants';
import { InventoryItem, MaterialRequest, Transaction } from './types';
import Home from './screens/Home';
import AdminDashboard from './screens/AdminDashboard';
import RequestForm from './screens/RequestForm';
import AdminLogin from './screens/AdminLogin';

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [requests, setRequests] = useState<MaterialRequest[]>(() => {
    const saved = localStorage.getItem('requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('transactions');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
  }, [inventory]);

  useEffect(() => {
    localStorage.setItem('requests', JSON.stringify(requests));
  }, [requests]);

  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (transaction: Omit<Transaction, 'id' | 'timestamp'>) => {
    const newTransaction: Transaction = {
      ...transaction,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
    };

    setTransactions(prev => [newTransaction, ...prev]);

    setInventory(prev => prev.map(item => {
      if (item.id === transaction.itemId) {
        const delta = transaction.type === 'in' ? transaction.quantity : -transaction.quantity;
        return { ...item, balance: Math.max(0, item.balance + delta) };
      }
      return item;
    }));
  };

  const addRequest = (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => {
    const newRequest: MaterialRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      status: 'pending',
    };
    setRequests(prev => [newRequest, ...prev]);
  };

  const updateRequestStatus = (id: string, status: 'pending' | 'served') => {
    const request = requests.find(r => r.id === id);
    if (!request) return;

    if (status === 'served' && request.status !== 'served') {
      // Deduct from inventory when served
      request.items.forEach(reqItem => {
        addTransaction({
          itemId: reqItem.itemId,
          type: 'out',
          quantity: reqItem.quantity,
          description: `Atendimento VTR ${request.vtr}`
        });
      });
    }

    setRequests(prev => prev.map(req => req.id === id ? { ...req, status } : req));
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50">
        <header className="bg-[#003366] text-white p-4 shadow-xl flex items-center justify-between sticky top-0 z-50">
          <Link to="/" className="flex items-center gap-3 group">
            <BucketTruckIcon className="w-10 h-10 text-white group-hover:text-[#FF8C00] transition-colors" />
            <div>
              <h1 className="text-xl font-bold tracking-tight">Linha Viva</h1>
              <p className="text-[10px] uppercase tracking-widest opacity-80">Itabaiana</p>
            </div>
          </Link>
          <div className="text-xs font-medium text-white/60 hidden sm:block">
            Controle de Frota e Materiais
          </div>
        </header>

        <main className="flex-1 overflow-y-auto">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route 
              path="/admin/dashboard" 
              element={
                <AdminDashboard 
                  inventory={inventory} 
                  requests={requests} 
                  addTransaction={addTransaction}
                  updateRequestStatus={updateRequestStatus}
                  setInventory={setInventory}
                />
              } 
            />
            <Route 
              path="/request" 
              element={<RequestForm inventory={inventory} addRequest={addRequest} />} 
            />
          </Routes>
        </main>

        <footer className="bg-white text-gray-400 text-[10px] p-3 text-center border-t">
          &copy; {new Date().getFullYear()} Linha Viva Itabaiana - Sistema de Gestão Interna
        </footer>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { useNavigate } from 'react-router-dom';

const Home: React.FC = () => {
  const navigate = useNavigate();

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] p-6 gap-8">
      <div className="text-center space-y-2 animate-fade-in">
        <h2 className="text-4xl font-extrabold text-[#003366]">Linha Viva Itabaiana</h2>
        <p className="text-gray-500 max-w-sm mx-auto">Sistema centralizado para controle de estoque e requisições de campo.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-3xl">
        <button
          onClick={() => navigate('/admin/login')}
          className="flex flex-col items-center justify-center p-10 bg-white border-2 border-[#003366] rounded-3xl shadow-lg hover:shadow-2xl hover:-translate-y-1 transition-all group"
        >
          <div className="p-6 bg-[#003366] rounded-2xl text-white mb-6 group-hover:scale-110 transition-transform">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <span className="text-2xl font-bold text-[#003366]">Administrador</span>
          <span className="text-sm text-gray-500 mt-2 text-center">Gestão de estoque, entradas e auditoria de pedidos</span>
        </button>

        <button
          onClick={() => navigate('/request')}
          className="flex flex-col items-center justify-center p-10 bg-white border-2 border-[#FF8C00] rounded-3xl shadow-lg hover:shadow-2xl hover:-translate-y-1 transition-all group"
        >
          <div className="p-6 bg-[#FF8C00] rounded-2xl text-white mb-6 group-hover:scale-110 transition-transform">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
          <span className="text-2xl font-bold text-[#FF8C00]">Solicitar Material</span>
          <span className="text-sm text-gray-500 mt-2 text-center">Requisições rápidas para viaturas em operação</span>
        </button>
      </div>
    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ADMIN_PASSWORD } from '../constants';

const AdminLogin: React.FC = () => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASSWORD) {
      sessionStorage.setItem('isAdmin', 'true');
      navigate('/admin/dashboard');
    } else {
      setError(true);
      setTimeout(() => setError(false), 2000);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[70vh] p-6">
      <div className="bg-white p-8 md:p-12 rounded-3xl shadow-2xl border w-full max-w-md animate-fade-in-up">
        <div className="text-center mb-8">
          <div className="bg-slate-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#003366]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 11c0 3.517-1.009 6.799-2.753 9.571m-1.197-3.59c1.612-2.852 2.533-6.12 2.533-9.571m0 0A5 5 0 1117 16m0 0a5 5 0 11-10 0" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-[#003366]">Área Administrativa</h2>
          <p className="text-sm text-gray-400 mt-1">Identifique-se para prosseguir</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-500 uppercase ml-1">Senha de Acesso</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className={`w-full p-4 border-2 rounded-2xl focus:ring-4 focus:ring-[#003366]/10 outline-none transition-all text-center text-xl tracking-widest ${error ? 'border-red-500 bg-red-50 text-red-900' : 'border-slate-100 focus:border-[#003366]'}`}
              placeholder="••••••"
              autoFocus
              required
            />
            {error && <p className="text-red-500 text-xs mt-2 text-center font-semibold">Credenciais incorretas!</p>}
          </div>
          <button
            type="submit"
            className="w-full bg-[#003366] text-white font-bold p-4 rounded-2xl hover:bg-[#002244] shadow-lg shadow-[#003366]/20 transition-all active:scale-95"
          >
            Acessar Painel
          </button>
          <button
            type="button"
            onClick={() => navigate('/')}
            className="w-full text-gray-400 text-sm font-medium hover:text-[#003366] transition-colors"
          >
            Voltar ao Início
          </button>
        </form>
      </div>
    </div>
  );
};

export default AdminLogin;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
  updateRequestStatus: (id: string, status: 'pending' | 'served') => void;
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
}

const AdminDashboard: React.FC<Props> = ({ 
  inventory, 
  requests, 
  addTransaction, 
  updateRequestStatus,
  setInventory
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'stock' | 'requests'>('stock');
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', balance: 0 });
  const [movement, setMovement] = useState({ itemId: '', quantity: 1, type: 'in' as 'in' | 'out', description: '' });

  useEffect(() => {
    if (sessionStorage.getItem('isAdmin') !== 'true') {
      navigate('/admin/login');
    }
  }, [navigate]);

  const handleExportXLSX = () => {
    if (typeof (window as any).XLSX === 'undefined') {
      alert("Erro ao carregar biblioteca Excel. Tente novamente em instantes.");
      return;
    }
    const XLSX = (window as any).XLSX;

    // Sheet 1: Inventory
    const stockData = inventory.map(item => ({
      'ID': item.id,
      'Material': item.name,
      'Saldo Atual': item.balance,
      'Status': item.balance <= 5 ? 'Crítico' : 'Normal'
    }));

    // Sheet 2: Requests
    const requestsData = requests.map(req => ({
      'ID': req.id,
      'Data/Hora': new Date(req.timestamp).toLocaleString('pt-BR'),
      'VTR': req.vtr,
      'Solicitante': req.requesterName,
      'Status': req.status === 'pending' ? 'Pendente' : 'Atendido',
      'Materiais': req.items.map(i => `${i.itemName} (${i.quantity})`).join(', ')
    }));

    const wb = XLSX.utils.book_new();
    const ws1 = XLSX.utils.json_to_sheet(stockData);
    const ws2 = XLSX.utils.json_to_sheet(requestsData);

    XLSX.utils.book_append_sheet(wb, ws1, "Estoque Atual");
    XLSX.utils.book_append_sheet(wb, ws2, "Solicitações");

    XLSX.writeFile(wb, `LinhaViva_Relatorio_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleAddStockItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.name) return;
    const item: InventoryItem = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      name: newItem.name,
      balance: newItem.balance,
    };
    setInventory(prev => [...prev, item]);
    setShowAddModal(false);
    setNewItem({ name: '', balance: 0 });
  };

  const handleMovementSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!movement.itemId) return;
    addTransaction(movement);
    setMovement({ itemId: '', quantity: 1, type: 'in', description: '' });
  };

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-6 animate-fade-in">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-6 md:p-8 rounded-3xl shadow-sm border border-slate-100">
        <div>
          <h2 className="text-3xl font-extrabold text-[#003366]">Painel de Controle</h2>
          <p className="text-gray-400 font-medium">Gestão administrativa Linha Viva Itabaiana</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <button 
            onClick={handleExportXLSX}
            className="flex-1 md:flex-none bg-green-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-green-700 shadow-lg shadow-green-100 transition-all flex items-center justify-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" />
            </svg>
            Exportar XLSX
          </button>
          <button 
            onClick={() => { sessionStorage.removeItem('isAdmin'); navigate('/'); }}
            className="flex-1 md:flex-none bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-bold hover:bg-slate-200 transition-all"
          >
            Sair
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-slate-200/50 p-1.5 rounded-2xl w-fit border border-slate-200">
        <button 
          onClick={() => setActiveTab('stock')}
          className={`px-8 py-3 rounded-xl font-bold transition-all ${activeTab === 'stock' ? 'bg-white shadow-md text-[#003366]' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Estoque
        </button>
        <button 
          onClick={() => setActiveTab('requests')}
          className={`px-8 py-3 rounded-xl font-bold transition-all relative ${activeTab === 'requests' ? 'bg-white shadow-md text-[#003366]' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Solicitações
          {requests.filter(r => r.status === 'pending').length > 0 && (
            <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[10px] text-white">
              {requests.filter(r => r.status === 'pending').length}
            </span>
          )}
        </button>
      </div>

      {activeTab === 'stock' ? (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          {/* Inventory Table */}
          <div className="lg:col-span-8 bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-6 bg-slate-50/50 border-b border-slate-100 flex justify-between items-center">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#003366]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4" />
                </svg>
                Saldo em Depósito
              </h3>
              <button 
                onClick={() => setShowAddModal(true)}
                className="text-sm bg-[#003366] text-white px-4 py-2 rounded-xl font-bold hover:bg-[#002244] shadow-lg shadow-[#003366]/20 transition-all"
              >
                + Novo Material
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50/80 text-[10px] uppercase font-black text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Item / Material</th>
                    <th className="px-6 py-4">Estoque</th>
                    <th className="px-6 py-4">Situação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {inventory.map(item => (
                    <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-6 py-5">
                        <div className="font-bold text-slate-700 group-hover:text-[#003366] transition-colors">{item.name}</div>
                        <div className="text-[10px] text-slate-400 font-mono mt-0.5">ID: {item.id}</div>
                      </td>
                      <td className="px-6 py-5">
                        <span className={`text-xl font-black ${item.balance <= 5 ? 'text-red-500' : 'text-slate-800'}`}>
                          {item.balance}
                        </span>
                      </td>
                      <td className="px-6 py-5">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider ${item.balance > 5 ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700 animate-pulse'}`}>
                          <span className={`mr-1.5 h-1.5 w-1.5 rounded-full ${item.balance > 5 ? 'bg-green-500' : 'bg-red-500'}`}></span>
                          {item.balance > 5 ? 'Estoque OK' : 'Crítico'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Quick Transaction Panel */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-8 h-fit">
              <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#FF8C00]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
                </svg>
                Lançar Movimento
              </h3>
              <form onSubmit={handleMovementSubmit} className="space-y-5">
                <div className="space-y-1.5">
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Material</label>
                  <select 
                    className="w-full p-3 border-2 border-slate-100 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-medium text-slate-700"
                    value={movement.itemId}
                    onChange={e => setMovement({...movement, itemId: e.target.value})}
                    required
                  >
