                      <option value="out" className="text-red-600">Saída (-)</option>
                    </select>
                  </div>
                  <div className="space-y-1.5">
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Qtd</label>
                    <input 
                      type="number" 
                      min="1"
                      className="w-full p-3 border-2 border-slate-100 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-bold text-slate-700"
                      value={movement.quantity}
                      onChange={e => setMovement({...movement, quantity: Number(e.target.value)})}
                      required
                    />
                  </div>
                </div>
                <div className="space-y-1.5">
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Observação</label>
                  <input 
                    type="text" 
                    className="w-full p-3 border-2 border-slate-100 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-medium text-slate-700"
                    value={movement.description}
                    onChange={e => setMovement({...movement, description: e.target.value})}
