                <button type="submit" className="w-full bg-[#FF8C00] text-white font-black py-4 rounded-2xl hover:bg-orange-600 shadow-xl shadow-orange-100 transition-all active:scale-95 uppercase tracking-widest">
                  Confirmar Lançamento
                </button>
              </form>
            </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-6">
          {requests.length === 0 ? (
            <div className="bg-white p-20 text-center rounded-3xl border border-slate-100 shadow-sm">
              <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0a2 2 0 01-2 2H6a2 2 0 01-2-2m16 0l-8 8-8-8" />
                </svg>
              </div>
              <h3 className="text-xl font-bold text-slate-800">Tudo limpo!</h3>
              <p className="text-slate-400">Nenhuma solicitação aguardando processamento.</p>
            </div>
          ) : (
            <div className="space-y-4">
              {requests.map(req => (
                <div key={req.id} className={`bg-white p-6 rounded-3xl shadow-sm border-l-8 transition-all hover:shadow-md ${req.status === 'served' ? 'border-green-500 opacity-75' : 'border-[#FF8C00] border-2 shadow-orange-50'}`}>
                  <div className="flex flex-col md:flex-row justify-between gap-6">
                    <div className="flex-1 space-y-4">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          <span className="bg-[#003366] text-white px-3 py-1 rounded-full text-xs font-black tracking-widest uppercase">
                            VTR {req.vtr}
                          </span>
                          <span className="text-[10px] text-slate-400 font-mono">#{req.id}</span>
                        </div>
                        <span className="text-xs font-medium text-slate-400 flex items-center gap-1">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                          </svg>
                          {new Date(req.timestamp).toLocaleString()}
                        </span>
                      </div>

                      <div className="space-y-1">
                        <h4 className="text-xl font-black text-slate-800">{req.requesterName}</h4>
                        <div className="flex flex-wrap gap-2 pt-1">
                          {req.items.map((item, idx) => (
                            <div key={idx} className="bg-slate-100 text-slate-700 px-3 py-1.5 rounded-xl text-xs font-bold border border-slate-200">
                              <span className="text-[#003366]">{item.quantity}x</span> {item.itemName}
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center justify-end md:w-48">
                      {req.status === 'pending' ? (
                        <button 
                          onClick={() => updateRequestStatus(req.id, 'served')}
                          className="w-full bg-green-600 text-white px-6 py-4 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-green-700 shadow-xl shadow-green-100 transition-all active:scale-95"
                        >
