                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Simple Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100] animate-fade-in">
          <div className="bg-white rounded-3xl p-8 w-full max-w-sm shadow-2xl border border-slate-100 animate-scale-up">
            <h3 className="text-2xl font-black text-[#003366] mb-6 text-center">Novo Material</h3>
            <form onSubmit={handleAddStockItem} className="space-y-6">
