                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Item</label>
                <input 
                  autoFocus
                  className="w-full p-4 border-2 border-slate-100 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-slate-700"
                  value={newItem.name}
                  onChange={e => setNewItem({...newItem, name: e.target.value})}
