              <div className="flex gap-3 pt-2">
                <button type="submit" className="flex-[2] bg-[#003366] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:bg-[#002244] shadow-xl shadow-[#003366]/20 transition-all">Salvar</button>
