import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { VEHICLES } from '../constants';
import { InventoryItem, RequestedItem, MaterialRequest } from '../types';

interface Props {
  inventory: InventoryItem[];
  addRequest: (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => void;
}

const RequestForm: React.FC<Props> = ({ inventory, addRequest }) => {
  const navigate = useNavigate();
  const [vtr, setVtr] = useState('');
  const [requesterName, setRequesterName] = useState('');
  const [selectedItems, setSelectedItems] = useState<RequestedItem[]>([]);
  const [currentItem, setCurrentItem] = useState({ itemId: '', quantity: 1 });
  const [isSuccess, setIsSuccess] = useState(false);

  // Filter items that have stock for the requester
  const availableItems = inventory.filter(i => i.balance > 0);

  const handleAddItem = () => {
    if (!currentItem.itemId) return;
    const item = inventory.find(i => i.id === currentItem.itemId);
    if (!item) return;

    if (currentItem.quantity > item.balance) {
      alert(`Quantidade superior ao estoque disponível (${item.balance} em estoque)`);
      return;
    }

    const existingIndex = selectedItems.findIndex(i => i.itemId === currentItem.itemId);
    if (existingIndex >= 0) {
      const updated = [...selectedItems];
      updated[existingIndex].quantity += currentItem.quantity;
      setSelectedItems(updated);
    } else {
      setSelectedItems(prev => [...prev, { itemId: item.id, itemName: item.name, quantity: currentItem.quantity }]);
    }
    setCurrentItem({ itemId: '', quantity: 1 });
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.itemId !== id));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItems.length === 0) {
      alert("Por favor, adicione pelo menos um item à sua solicitação.");
      return;
    }

    addRequest({
      vtr,
      requesterName,
      items: selectedItems
    });

    setIsSuccess(true);
    setTimeout(() => {
      navigate('/');
    }, 2500);
  };

  if (isSuccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] p-6 text-center space-y-6 animate-fade-in">
        <div className="bg-green-100 p-8 rounded-full text-green-600 shadow-xl shadow-green-50 animate-bounce">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-black text-[#003366]">Solicitação Enviada!</h2>
          <p className="text-slate-500 font-medium max-w-xs mx-auto">Obrigado, {requesterName}. Sua requisição para a VTR {vtr} foi registrada.</p>
        </div>
        <div className="text-[10px] text-slate-300 uppercase tracking-widest font-black pt-10">Redirecionando...</div>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-3xl mx-auto space-y-6 animate-fade-in">
      <div className="bg-white p-8 md:p-12 rounded-3xl shadow-xl border border-slate-100">
        <div className="mb-10 text-center">
          <h2 className="text-3xl font-black text-[#003366]">Novo Pedido</h2>
          <p className="text-slate-400 font-medium mt-1">Requisição de materiais para viaturas em campo</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Section 1: Identity */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Sua Viatura (VTR)</label>
              <select 
                className="w-full p-4 border-2 border-slate-50 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-[#003366]"
                value={vtr}
                onChange={e => setVtr(e.target.value)}
                required
              >
                <option value="">Selecione...</option>
                {VEHICLES.map(v => <option key={v} value={v}>Viatura {v}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Responsável</label>
              <input 
                type="text" 
                className="w-full p-4 border-2 border-slate-50 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-slate-700"
                placeholder="Seu nome completo"
                value={requesterName}
                onChange={e => setRequesterName(e.target.value)}
                required
              />
            </div>
          </div>

          <hr className="border-slate-100" />

          {/* Section 2: Items Addition */}
          <div className="bg-slate-50/50 p-6 rounded-3xl space-y-6 border border-slate-100 relative">
            <div className="absolute -top-3 left-6 bg-white px-3 py-1 text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-100 rounded-full">
              Seleção de Materiais
            </div>

            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-[3] space-y-1">
                <select 
                  className="w-full p-4 border-2 border-white rounded-2xl bg-white focus:border-[#FF8C00] outline-none transition-all font-medium text-slate-700 shadow-sm"
                  value={currentItem.itemId}
                  onChange={e => setCurrentItem({...currentItem, itemId: e.target.value})}
                >
                  <option value="">Buscar material...</option>
                  {availableItems.map(i => (
                    <option key={i.id} value={i.id}>{i.name} (Saldo: {i.balance})</option>
                  ))}
                </select>
              </div>
              <div className="flex-1 space-y-1">
                <input 
                  type="number" 
                  min="1"
                  placeholder="Qtd"
                  className="w-full p-4 border-2 border-white rounded-2xl bg-white focus:border-[#FF8C00] outline-none transition-all font-black text-[#FF8C00] shadow-sm text-center"
                  value={currentItem.quantity}
                  onChange={e => setCurrentItem({...currentItem, quantity: Number(e.target.value)})}
                />
              </div>
              <button 
                type="button"
                onClick={handleAddItem}
                className="bg-[#FF8C00] text-white px-8 py-4 rounded-2xl font-black text-xl hover:bg-orange-600 shadow-xl shadow-orange-100 transition-all active:scale-95"
              >
                +
              </button>
            </div>

            {selectedItems.length > 0 && (
              <div className="space-y-3 animate-fade-in-up">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Lista de Solicitação</h4>
                <div className="grid gap-2">
                  {selectedItems.map((item, idx) => (
                    <div key={idx} className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm group hover:border-[#FF8C00]/30 transition-colors">
                      <div className="flex items-center gap-3">
                        <span className="bg-[#FF8C00] text-white w-10 h-10 flex items-center justify-center rounded-xl font-black text-sm">
                          {item.quantity}
                        </span>
                        <span className="font-bold text-slate-700">{item.itemName}</span>
                      </div>
                      <button 
                        type="button"
                        onClick={() => removeItem(item.itemId)}
                        className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button
              type="submit"
              className="flex-[2] bg-[#003366] text-white font-black py-5 rounded-2xl shadow-2xl shadow-[#003366]/20 hover:bg-[#002244] transition-all active:scale-[0.98] uppercase tracking-widest"
            >
              Finalizar Solicitação
            </button>
            <button
              type="button"
              onClick={() => navigate('/')}
              className="flex-1 bg-white border-2 border-slate-100 text-slate-400 font-bold py-5 rounded-2xl hover:bg-slate-50 transition-all"
            >
              Cancelar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default RequestForm;

{
  "name": "Linha Viva Itabaiana",
  "description": "Sistema de Controle de Materiais e Solicitação para Frota Itabaiana",
  "requestFramePermissions": []
}

import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import { BucketTruckIcon } from './components/Icons';
import { INITIAL_INVENTORY } from './constants';
import { InventoryItem, MaterialRequest, Transaction } from './types';
import Home from './screens/Home';
import AdminDashboard from './screens/AdminDashboard';
import RequestForm from './screens/RequestForm';
import AdminLogin from './screens/AdminLogin';

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [requests, setRequests] = useState<MaterialRequest[]>(() => {
    const saved = localStorage.getItem('requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('transactions');
    return saved ? JSON.parse(saved) : [];
  });

  // Simulated Google Sheets Sync
  const syncToGoogleSheets = async (data: any, type: string) => {
    console.info(`[Google Sheets Sync] Salvando ${type} na planilha:`, data);
    // Em um cenário real, aqui teríamos uma chamada para um Google Apps Script Web App
    // fetch('https://script.google.com/macros/s/YOUR_SCRIPT_ID/exec', { method: 'POST', body: JSON.stringify(data) });
  };

  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
  }, [inventory]);

  useEffect(() => {
    localStorage.setItem('requests', JSON.stringify(requests));
  }, [requests]);

  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (transaction: Omit<Transaction, 'id' | 'timestamp'>) => {
    const newTransaction: Transaction = {
      ...transaction,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
    };

    setTransactions(prev => [newTransaction, ...prev]);

    setInventory(prev => prev.map(item => {
      if (item.id === transaction.itemId) {
        const delta = transaction.type === 'in' ? transaction.quantity : -transaction.quantity;
        return { ...item, balance: Math.max(0, item.balance + delta) };
      }
      return item;
    }));

    syncToGoogleSheets(newTransaction, 'Movimentação de Estoque');
  };

  const addRequest = (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => {
    const newRequest: MaterialRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      status: 'pending',
    };
    setRequests(prev => [newRequest, ...prev]);
    syncToGoogleSheets(newRequest, 'Nova Solicitação');
  };

  const updateRequestStatus = (id: string, status: 'pending' | 'served') => {
    const request = requests.find(r => r.id === id);
    if (!request) return;

    if (status === 'served' && request.status !== 'served') {
      // Deduct from inventory when served
      request.items.forEach(reqItem => {
        addTransaction({
          itemId: reqItem.itemId,
          type: 'out',
          quantity: reqItem.quantity,
          description: `Atendimento VTR ${request.vtr}`
        });
      });
    }

    setRequests(prev => prev.map(req => req.id === id ? { ...req, status } : req));
    syncToGoogleSheets({ id, status, vtr: request.vtr }, 'Atualização de Status');
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50">
        <header className="bg-[#003366] text-white p-4 shadow-xl flex items-center justify-between sticky top-0 z-50">
          <Link to="/" className="flex items-center gap-3 group">
            <BucketTruckIcon className="w-10 h-10 text-white group-hover:text-[#FF8C00] transition-colors" />
            <div>
              <h1 className="text-xl font-bold tracking-tight">Linha Viva</h1>
              <p className="text-[10px] uppercase tracking-widest opacity-80">Itabaiana</p>
            </div>
          </Link>
          <div className="text-xs font-medium text-white/60 hidden sm:block">
            Controle de Frota e Materiais
          </div>
        </header>

        <main className="flex-1 overflow-y-auto">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route 
              path="/admin/dashboard" 
              element={
                <AdminDashboard 
                  inventory={inventory} 
                  requests={requests} 
                  addTransaction={addTransaction}
                  updateRequestStatus={updateRequestStatus}
                  setInventory={setInventory}
                />
              } 
            />
            <Route 
              path="/request" 
              element={<RequestForm inventory={inventory} addRequest={addRequest} />} 
            />
          </Routes>
        </main>

        <footer className="bg-white text-gray-400 text-[10px] p-3 text-center border-t">
          &copy; {new Date().getFullYear()} Linha Viva Itabaiana - Sistema de Gestão Interna
        </footer>
      </div>
    </HashRouter>
  );
};

export default App;

export const COLORS = {
  primary: '#003366', // Blue
  secondary: '#FF8C00', // Orange
  accent: '#FFFFFF', // White
};

// Unique vehicle list from prompt (removing duplicates like 1811 and 1859)
const RAW_VEHICLES = [
  "1645", "1700", "1711", "1769", "1770", "1811", "1859", 
  "1847", "1845", "1811", "1859", "4001", "4006", "4013", 
  "4014", "4015", "4016", "4020", "4025"
];

export const VEHICLES = Array.from(new Set(RAW_VEHICLES)).sort((a, b) => Number(a) - Number(b));

export const ADMIN_PASSWORD = "Dsa21";

export const INITIAL_INVENTORY = [
  { id: '1', name: 'Luva Isolante Classe 2', balance: 10 },
  { id: '2', name: 'Bastão de Manobra', balance: 5 },
  { id: '3', name: 'Cobertura de Linha Viva', balance: 15 },
