import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { VEHICLES } from '../constants';
import { InventoryItem, RequestedItem, MaterialRequest } from '../types';

interface Props {
  inventory: InventoryItem[];
  addRequest: (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => void;
  isSyncing: boolean;
}

const RequestForm: React.FC<Props> = ({ inventory, addRequest, isSyncing }) => {
  const navigate = useNavigate();
  const [vtr, setVtr] = useState('');
  const [requesterName, setRequesterName] = useState('');
  const [selectedItems, setSelectedItems] = useState<RequestedItem[]>([]);
  const [currentItem, setCurrentItem] = useState({ itemId: '', quantity: 1 });
  const [isSuccess, setIsSuccess] = useState(false);

  const availableItems = inventory.filter(i => i.balance > 0);

  const handleAddItem = () => {
    if (!currentItem.itemId) return;
    const item = inventory.find(i => i.id === currentItem.itemId);
    if (!item) return;

    if (currentItem.quantity > item.balance) {
      alert(`Quantidade superior ao estoque disponível (${item.balance} em estoque)`);
      return;
    }

    const existingIndex = selectedItems.findIndex(i => i.itemId === currentItem.itemId);
    if (existingIndex >= 0) {
      const updated = [...selectedItems];
      updated[existingIndex].quantity += currentItem.quantity;
      setSelectedItems(updated);
    } else {
      setSelectedItems(prev => [...prev, { itemId: item.id, itemName: item.name, quantity: currentItem.quantity }]);
    }
    setCurrentItem({ itemId: '', quantity: 1 });
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.itemId !== id));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItems.length === 0) {
      alert("Por favor, adicione pelo menos um item à sua solicitação.");
      return;
    }

    addRequest({
      vtr,
      requesterName,
      items: selectedItems
    });

    setIsSuccess(true);
    setTimeout(() => {
      navigate('/');
    }, 2500);
  };

  if (isSuccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] p-6 text-center space-y-6 animate-fade-in">
        <div className="bg-green-100 p-8 rounded-full text-green-600 shadow-xl shadow-green-50 animate-bounce">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-black text-[#003366]">Solicitação Enviada!</h2>
          <p className="text-slate-500 font-medium max-w-xs mx-auto">Sua requisição foi registrada e sincronizada.</p>
        </div>
        <div className="text-[10px] text-slate-300 uppercase tracking-widest font-black pt-10">Redirecionando...</div>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-3xl mx-auto space-y-6 animate-fade-in">
      <div className="bg-white p-8 md:p-12 rounded-3xl shadow-xl border border-slate-100">
        <div className="mb-10 text-center">
          <h2 className="text-3xl font-black text-[#003366]">Novo Pedido</h2>
          <p className="text-slate-400 font-medium mt-1">Requisição de materiais para viaturas em campo</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Sua Viatura (VTR)</label>
              <select 
                className="w-full p-4 border-2 border-slate-50 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-[#003366]"
                value={vtr}
                onChange={e => setVtr(e.target.value)}
                required
              >
                <option value="">Selecione...</option>
                {VEHICLES.map(v => <option key={v} value={v}>Viatura {v}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Responsável</label>
              <input 
                type="text" 
                className="w-full p-4 border-2 border-slate-50 rounded-2xl bg-slate-50 focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-slate-700"
                placeholder="Seu nome completo"
                value={requesterName}
                onChange={e => setRequesterName(e.target.value)}
                required
              />
            </div>
          </div>

          <hr className="border-slate-100" />

          <div className="bg-slate-50/50 p-6 rounded-3xl space-y-6 border border-slate-100 relative">
            <div className="absolute -top-3 left-6 bg-white px-3 py-1 text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-100 rounded-full">Materiais</div>

            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-[3] space-y-1">
                <select 
                  className="w-full p-4 border-2 border-white rounded-2xl bg-white focus:border-[#FF8C00] outline-none transition-all font-medium text-slate-700 shadow-sm"
                  value={currentItem.itemId}
                  onChange={e => setCurrentItem({...currentItem, itemId: e.target.value})}
                >
                  <option value="">Buscar material...</option>
                  {availableItems.map(i => (
                    <option key={i.id} value={i.id}>{i.name} (Saldo: {i.balance})</option>
                  ))}
                </select>
              </div>
              <div className="flex-1 space-y-1">
                <input 
                  type="number" 
                  min="1"
                  className="w-full p-4 border-2 border-white rounded-2xl bg-white focus:border-[#FF8C00] outline-none transition-all font-black text-[#FF8C00] shadow-sm text-center"
                  value={currentItem.quantity}
                  onChange={e => setCurrentItem({...currentItem, quantity: Number(e.target.value)})}
                />
              </div>
              <button type="button" onClick={handleAddItem} className="bg-[#FF8C00] text-white px-8 py-4 rounded-2xl font-black text-xl hover:bg-orange-600 transition-all">+</button>
            </div>

            {selectedItems.length > 0 && (
              <div className="space-y-3">
                {selectedItems.map((item, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                    <div className="flex items-center gap-3">
                      <span className="bg-[#FF8C00] text-white w-10 h-10 flex items-center justify-center rounded-xl font-black text-sm">{item.quantity}</span>
                      <span className="font-bold text-slate-700">{item.itemName}</span>
                    </div>
                    <button type="button" onClick={() => removeItem(item.itemId)} className="text-slate-300 hover:text-red-500">Excluir</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <button
            type="submit"
            disabled={isSyncing}
            className={`w-full font-black py-5 rounded-2xl shadow-2xl transition-all uppercase tracking-widest ${isSyncing ? 'bg-slate-300 cursor-not-allowed' : 'bg-[#003366] text-white hover:bg-[#002244]'}`}
          >
            {isSyncing ? 'Sincronizando Banco de Dados...' : 'Finalizar Solicitação'}
          </button>
        </form>
      </div>
    </div>
  );
};

