import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import { BucketTruckIcon } from './components/Icons';
import { INITIAL_INVENTORY, GOOGLE_SHEETS_URL } from './constants';
import { InventoryItem, MaterialRequest, Transaction } from './types';
import Home from './screens/Home';
import AdminDashboard from './screens/AdminDashboard';
import RequestForm from './screens/RequestForm';
import AdminLogin from './screens/AdminLogin';

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [requests, setRequests] = useState<MaterialRequest[]>(() => {
    const saved = localStorage.getItem('requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [sheetsUrl, setSheetsUrl] = useState<string>(() => {
    const saved = localStorage.getItem('sheetsUrl');
    return saved || GOOGLE_SHEETS_URL;
  });

  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
  }, [inventory]);

  useEffect(() => {
    localStorage.setItem('requests', JSON.stringify(requests));
  }, [requests]);

  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('sheetsUrl', sheetsUrl);
  }, [sheetsUrl]);

  const syncToGoogleSheets = async (payload: any, type: string) => {
    const urlToUse = sheetsUrl || GOOGLE_SHEETS_URL;
    if (!urlToUse) {
      console.warn("URL do Google Sheets não configurada.");
      return;
    }

    setIsSyncing(true);
    try {
      // Usamos form-data simples ou JSON. No caso de Apps Script 'no-cors' funciona para envio.
      // Para garantir que o Apps Script receba, enviamos como string no corpo.
      await fetch(urlToUse, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          type,
          payload,
          timestamp: new Date().toISOString()
        })
      });
      console.info(`Dados enviados para sincronização: ${type}`);
    } catch (error) {
      console.error("Erro na comunicação com Google Sheets:", error);
    } finally {
      // Como o modo é no-cors, não temos confirmação de sucesso, 
      // mas o navegador tenta enviar os pacotes.
      setTimeout(() => setIsSyncing(false), 1000);
    }
  };

  const addTransaction = (transaction: Omit<Transaction, 'id' | 'timestamp'>) => {
    const newTransaction: Transaction = {
      ...transaction,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
    };

    setTransactions(prev => [newTransaction, ...prev]);

    setInventory(prev => prev.map(item => {
      if (item.id === transaction.itemId) {
        const delta = transaction.type === 'in' ? transaction.quantity : -transaction.quantity;
        return { ...item, balance: Math.max(0, item.balance + delta) };
      }
      return item;
    }));

    syncToGoogleSheets(newTransaction, 'MOVIMENTACAO_ESTOQUE');
  };

  const addRequest = (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => {
    const newRequest: MaterialRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      status: 'pending',
    };
    setRequests(prev => [newRequest, ...prev]);
    syncToGoogleSheets(newRequest, 'NOVA_SOLICITACAO');
  };

  const updateRequestStatus = (id: string, status: 'pending' | 'served') => {
    const request = requests.find(r => r.id === id);
    if (!request) return;

    if (status === 'served' && request.status !== 'served') {
      request.items.forEach(reqItem => {
        addTransaction({
          itemId: reqItem.itemId,
          type: 'out',
          quantity: reqItem.quantity,
          description: `Atendimento VTR ${request.vtr}`
        });
      });
    }

    setRequests(prev => prev.map(req => req.id === id ? { ...req, status } : req));
    syncToGoogleSheets({ id, status, vtr: request.vtr }, 'ATUALIZACAO_STATUS_PEDIDO');
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50">
        <header className="bg-[#003366] text-white p-4 shadow-xl flex items-center justify-between sticky top-0 z-50">
          <Link to="/" className="flex items-center gap-3 group">
            <BucketTruckIcon className="w-10 h-10 text-white group-hover:text-[#FF8C00] transition-colors" />
            <div>
              <h1 className="text-xl font-bold tracking-tight">Linha Viva</h1>
              <p className="text-[10px] uppercase tracking-widest opacity-80">Itabaiana</p>
            </div>
          </Link>
          <div className="flex items-center gap-4">
            {isSyncing && (
              <div className="flex items-center gap-2 text-[10px] bg-blue-500/20 px-2 py-1 rounded-full animate-pulse">
                <span className="w-2 h-2 bg-blue-400 rounded-full"></span>
                Sincronizando...
              </div>
            )}
            <div className="text-xs font-medium text-white/60 hidden sm:block">
              Controle de Frota e Materiais
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route 
              path="/admin/dashboard" 
              element={
                <AdminDashboard 
                  inventory={inventory} 
                  requests={requests} 
                  addTransaction={addTransaction}
                  updateRequestStatus={updateRequestStatus}
                  setInventory={setInventory}
                  sheetsUrl={sheetsUrl}
                  setSheetsUrl={setSheetsUrl}
                />
              } 
            />
            <Route 
              path="/request" 
              element={<RequestForm inventory={inventory} addRequest={addRequest} isSyncing={isSyncing} />} 
            />
          </Routes>
        </main>

        <footer className="bg-white text-gray-400 text-[10px] p-3 text-center border-t">
          &copy; {new Date().getFullYear()} Linha Viva Itabaiana - Sistema de Gestão Interna
        </footer>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';
import { GOOGLE_SHEETS_URL } from '../constants';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
  updateRequestStatus: (id: string, status: 'pending' | 'served') => void;
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
  sheetsUrl: string;
  setSheetsUrl: (url: string) => void;
}

const AdminDashboard: React.FC<Props> = ({ 
  inventory, 
  requests, 
  addTransaction, 
  updateRequestStatus,
  setInventory,
  sheetsUrl,
  setSheetsUrl
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'stock' | 'requests' | 'config'>('stock');
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', balance: 0 });
  const [movement, setMovement] = useState({ itemId: '', quantity: 1, type: 'in' as 'in' | 'out', description: '' });

  useEffect(() => {
    if (sessionStorage.getItem('isAdmin') !== 'true') {
      navigate('/admin/login');
    }
  }, [navigate]);

  const handleExportXLSX = () => {
    if (typeof (window as any).XLSX === 'undefined') {
      alert("Erro ao carregar biblioteca Excel. Tente novamente em instantes.");
      return;
    }
    const XLSX = (window as any).XLSX;

    const stockData = inventory.map(item => ({
      'ID': item.id,
      'Material': item.name,
      'Saldo Atual': item.balance,
      'Status': item.balance <= 5 ? 'Crítico' : 'Normal'
    }));

    const requestsData = requests.map(req => ({
      'ID': req.id,
      'Data/Hora': new Date(req.timestamp).toLocaleString('pt-BR'),
      'VTR': req.vtr,
      'Solicitante': req.requesterName,
      'Status': req.status === 'pending' ? 'Pendente' : 'Atendido',
      'Materiais': req.items.map(i => `${i.itemName} (${i.quantity})`).join(', ')
    }));

    const wb = XLSX.utils.book_new();
    const ws1 = XLSX.utils.json_to_sheet(stockData);
    const ws2 = XLSX.utils.json_to_sheet(requestsData);

    XLSX.utils.book_append_sheet(wb, ws1, "Estoque Atual");
    XLSX.utils.book_append_sheet(wb, ws2, "Solicitações");

    XLSX.writeFile(wb, `LinhaViva_Relatorio_${new Date().toISOString().split('T')[0]}.xlsx`);
