                    >
                      <option value="in" className="text-green-600">Entrada</option>
                      <option value="out" className="text-red-600">Saída</option>
                    </select>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Qtd</label>
                    <input 
                      type="number" 
                      min="1"
                      className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-black text-slate-700"
                      value={movement.quantity}
