payload.text:
Para corrigir a visualização na planilha e garantir que cada item seja registrado em sua própria célula (em vez de um bloco de texto JSON) e com datas formatadas para o Brasil (pt-BR), precisamos atualizar a lógica de sincronização no **App.tsx** e você precisará atualizar seu **Google Apps Script**.

### 1. Novo Código para o Google Apps Script (Copie e substitua na sua planilha)

Este script agora cria três abas: **Solicitacoes**, **Movimentacoes** e **Estoque_Atual**, organizando cada item individualmente.

```javascript
function doPost(e) {
  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;

    // Formatação de data e hora para pt-BR (Brasil)
    var timestamp = Utilities.formatDate(new Date(), "GMT-3", "dd/MM/yyyy HH:mm:ss");

    if (type === 'NOVA_SOLICITACAO') {
      var sheet = getOrCreateSheet(ss, "Solicitacoes", ["DATA/HORA", "VTR", "SOLICITANTE", "MATERIAL", "QUANTIDADE", "STATUS", "ID_PEDIDO"]);
      // IMPORTANTE: Grava cada item do pedido em uma linha diferente
      payload.items.forEach(function(item) {
        sheet.appendRow([
          timestamp,
          payload.vtr,
          payload.requesterName,
          item.itemName,
          item.quantity,
          "PENDENTE",
          payload.id
        ]);
      });
    } 
    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = getOrCreateSheet(ss, "Movimentacoes", ["DATA/HORA", "TIPO", "ID_MATERIAL", "MATERIAL", "QUANTIDADE", "MOTIVO"]);
      sheet.appendRow([
        timestamp,
        payload.type === 'in' ? 'ENTRADA' : 'SAIDA',
        payload.itemId,
        payload.itemName || "N/A",
        payload.quantity,
        payload.description || "Lançamento Manual"
      ]);
    }
    else if (type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName("Solicitacoes");
      if (sheet) {
        var rows = sheet.getDataRange().getValues();
        for (var i = 1; i < rows.length; i++) {
          if (rows[i][6] === payload.id) { // Coluna ID_PEDIDO
            sheet.getRange(i + 1, 6).setValue("ATENDIDO"); // Coluna STATUS
          }
        }
      }
    }

    return ContentService.createTextOutput("Sucesso").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Erro: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  }
}

function getOrCreateSheet(ss, name, headers) {
  var sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    sheet.appendRow(headers);
    sheet.setFrozenRows(1);
    sheet.getRange(1, 1, 1, headers.length).setFontWeight("bold").setBackground("#f3f3f3");
  }
  return sheet;
}
```

### 2. Alterações no App.tsx

Vou ajustar a função `addTransaction` para que ela envie também o nome do material, facilitando a identificação na planilha sem precisar cruzar dados manualmente.

