payload.text:
Entendi o problema. Quando você faz uma **Movimentação Manual**, o sistema está enviando apenas o log daquela operação, e o script da planilha pode estar interpretando mal ou você deseja que o saldo real seja atualizado em uma aba específica.

Para resolver, fiz as seguintes alterações:
1.  **App.tsx**: Agora, toda vez que o estoque muda (seja por pedido ou manual), o sistema envia a lista completa e atualizada para a aba **Estoque_Atual**, garantindo que ela seja sempre um espelho do seu inventário.
2.  **AdminDashboard.tsx**: Corrigi as cores dos textos nos campos de seleção e input da "Movimentação Manual" para que fiquem pretos e legíveis, conforme apontado na sua imagem.

### 1. Novo Código para o Google Apps Script (Substitua o antigo)

Este script é mais robusto e lida com as três abas separadamente:

```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000); // Evita conflitos de gravação simultânea
  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;
    var timestamp = Utilities.formatDate(new Date(), "GMT-3", "dd/MM/yyyy HH:mm:ss");

    if (type === 'NOVA_SOLICITACAO') {
      var sheet = getOrCreateSheet(ss, "Solicitacoes", ["DATA/HORA", "VTR", "SOLICITANTE", "MATERIAL", "QUANTIDADE", "STATUS", "ID_PEDIDO"]);
      payload.items.forEach(function(item) {
        sheet.appendRow([timestamp, payload.vtr, payload.requesterName, item.itemName, item.quantity, "PENDENTE", payload.id]);
      });
    } 
    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = getOrCreateSheet(ss, "Movimentacoes", ["DATA/HORA", "TIPO", "ID_MATERIAL", "MATERIAL", "QUANTIDADE", "MOTIVO"]);
      sheet.appendRow([timestamp, payload.type === 'in' ? 'ENTRADA' : 'SAIDA', payload.itemId, payload.itemName || "N/A", payload.quantity, payload.description || "Lançamento Manual"]);
    }
    else if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      // Limpa e sobrescreve a aba de estoque atual para manter o saldo sempre correto
      var sheet = getOrCreateSheet(ss, "Estoque_Atual", ["ID", "MATERIAL", "SALDO ATUAL", "ULTIMA ATUALIZACAO"]);
      sheet.clearContents();
      sheet.appendRow(["ID", "MATERIAL", "SALDO ATUAL", "ULTIMA ATUALIZACAO"]);
      payload.forEach(function(item) {
        sheet.appendRow([item.id, item.name, item.balance, timestamp]);
      });
      sheet.getRange(1, 1, 1, 4).setFontWeight("bold").setBackground("#f3f3f3");
    }

    return ContentService.createTextOutput("Sucesso").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Erro: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  } finally {
    lock.releaseLock();
  }
}

function getOrCreateSheet(ss, name, headers) {
  var sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    sheet.appendRow(headers);
    sheet.setFrozenRows(1);
  }
  return sheet;
}
