O problema de "parar de comunicar" geralmente acontece por dois motivos principais no Google Sheets:
1.  **Múltiplas requisições simultâneas:** O Google Sheets tem um "Lock" (trava) que falha se receber 10 pedidos ao mesmo tempo. No código anterior, ao atender um pedido com vários itens, o app disparava um POST para cada item instantaneamente.
2.  **CORS/Redirecionamento:** O Google Apps Script redireciona a requisição. O `fetch` precisa lidar com isso silenciosamente.

Vou atualizar o `App.tsx` para **agrupar as atualizações** em um único envio e melhorar a robustez da conexão.

### 1. Atualização do Script (Importante)
Certifique-se de que seu script no Google Sheets seja exatamente este (reimplante como **"Qualquer pessoa"**):

```javascript
function doGet(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName("Estoque_Atual");
  if (!sheet) return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);
  var data = sheet.getDataRange().getValues();
  var result = [];
  for (var i = 1; i < data.length; i++) {
    result.push({ id: String(data[i][0]), name: String(data[i][1]), balance: Number(data[i][2]) });
  }
  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(15000);
  try {
    var data = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var timestamp = Utilities.formatDate(new Date(), "GMT-3", "dd/MM/yyyy HH:mm:ss");

    if (data.type === 'NOVA_SOLICITACAO') {
      var sheet = getOrCreateSheet(ss, "Solicitacoes", ["DATA/HORA", "VTR", "SOLICITANTE", "MATERIAL", "QUANTIDADE", "STATUS", "ID_PEDIDO"]);
      data.payload.items.forEach(function(item) {
        sheet.appendRow([timestamp, data.payload.vtr, data.payload.requesterName, item.itemName, item.quantity, "PENDENTE", data.payload.id]);
      });
    } 
    else if (data.type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = getOrCreateSheet(ss, "Estoque_Atual", ["ID", "MATERIAL", "SALDO ATUAL", "ULTIMA ATUALIZACAO"]);
      if (sheet.getLastRow() > 1) sheet.deleteRows(2, sheet.getLastRow() - 1);
      var rows = data.payload.map(function(item) { return [item.id, item.name, item.balance, timestamp]; });
      if (rows.length > 0) sheet.getRange(2, 1, rows.length, 4).setValues(rows);
    }
    else if (data.type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName("Solicitacoes");
      if (sheet) {
        var values = sheet.getDataRange().getValues();
        for (var i = 1; i < values.length; i++) {
          if (values[i][6] == data.payload.id) sheet.getRange(i + 1, 6).setValue("ATENDIDO");
        }
      }
    }
    return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
  } catch (f) {
    return ContentService.createTextOutput("Erro").setMimeType(ContentService.MimeType.TEXT);
  } finally {
    lock.releaseLock();
  }
}

function getOrCreateSheet(ss, name, headers) {
  var sheet = ss.getSheetByName(name);
  if (!sheet) { sheet = ss.insertSheet(name); sheet.appendRow(headers); }
  return sheet;
}
```

