  const fetchFromSheets = useCallback(async () => {
    const urlToUse = sheetsUrl || GOOGLE_SHEETS_URL;
    if (!urlToUse) return;

    setIsSyncing(true);
    try {
      // O parâmetro 'nocache' garante que o Google Apps Script retorne dados novos
      const response = await fetch(`${urlToUse}?nocache=${Date.now()}`);
      if (response.ok) {
        const cloudData = await response.json();
        if (Array.isArray(cloudData) && cloudData.length > 0) {
          setInventory(cloudData);
          setLastSync(Date.now());
          localStorage.setItem('inventory', JSON.stringify(cloudData));
        }
      }
    } catch (error) {
      console.error("Linha Viva: Erro ao baixar dados da planilha", error);
    } finally {
      setIsSyncing(false);
    }
  }, [sheetsUrl]);

  // Envia dados para a nuvem (POST)
  const syncToGoogleSheets = async (payload: any, type: string) => {
    const urlToUse = sheetsUrl || GOOGLE_SHEETS_URL;
    if (!urlToUse) return;

    setIsSyncing(true);
    try {
      await fetch(urlToUse, {
        method: 'POST',
        mode: 'no-cors', // Fundamental para integração com Google Apps Script
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type, payload })
      });
    } catch (error) {
      console.error("Linha Viva: Falha na sincronização", error);
    } finally {
      // Pequeno delay para feedback visual e para evitar spam de rede
      setTimeout(() => setIsSyncing(false), 1200);
    }
  };

  useEffect(() => {
    fetchFromSheets();
  }, [fetchFromSheets]);

  useEffect(() => {
    localStorage.setItem('requests', JSON.stringify(requests));
  }, [requests]);

  useEffect(() => {
    localStorage.setItem('sheetsUrl', sheetsUrl);
  }, [sheetsUrl]);

  const addTransaction = (transaction: Omit<Transaction, 'id' | 'timestamp'>) => {
    const updatedInv = inventory.map(item => {
      if (item.id === transaction.itemId) {
        const delta = transaction.type === 'in' ? transaction.quantity : -transaction.quantity;
        return { ...item, balance: Math.max(0, item.balance + delta) };
      }
      return item;
    });
    setInventory(updatedInv);
    localStorage.setItem('inventory', JSON.stringify(updatedInv));
    syncToGoogleSheets(updatedInv, 'ATUALIZAR_ESTOQUE_TOTAL');
  };

  const addRequest = (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => {
    const newRequest: MaterialRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      status: 'pending',
    };
    setRequests(prev => [newRequest, ...prev]);
    syncToGoogleSheets(newRequest, 'NOVA_SOLICITACAO');
