import { InventoryItem, RequestedItem, MaterialRequest } from '../types';

interface Props {
  inventory: InventoryItem[];
  addRequest: (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => void;
  isSyncing: boolean;
}

const RequestForm: React.FC<Props> = ({ inventory, addRequest, isSyncing }) => {
  const navigate = useNavigate();
  const [vtr, setVtr] = useState('');
  const [requesterName, setRequesterName] = useState('');
  const [selectedItems, setSelectedItems] = useState<RequestedItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentItem, setCurrentItem] = useState({ itemId: '', quantity: 1 });
  const [isSuccess, setIsSuccess] = useState(false);

  // Filtro de segurança: remove itens que pareçam VTRs ou tags de sistema
  const availableItems = useMemo(() => {
    return inventory.filter(i => {
      const name = String(i.name).trim().toUpperCase();
      const isVtr = VEHICLES.includes(name) || VEHICLES.includes(name.replace('VTR', '').trim());
      const isSystemTag = ['NOVA_SOLICITACAO', 'ATUALIZAR_ESTOQUE_TOTAL', 'ATUALIZACAO_STATUS_PEDIDO', 'MOVIMENTACAO_ESTOQUE'].includes(name);
      const hasBalance = i.balance > 0;
      return hasBalance && !isVtr && !isSystemTag && name.length > 3;
    });
  }, [inventory]);

  // Filtra a lista baseada no que o usuário digita
  const filteredOptions = useMemo(() => {
    if (!searchTerm) return [];
    return availableItems.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      item.id.includes(searchTerm)
    ).slice(0, 8); // Limita a 8 resultados para não poluir a tela
  }, [searchTerm, availableItems]);

  const handleAddItem = (item?: InventoryItem) => {
    const targetItem = item || availableItems.find(i => i.id === currentItem.itemId);
    if (!targetItem) return;

    if (currentItem.quantity > targetItem.balance) {
      alert(`Ops! Só temos ${targetItem.balance} em estoque para este material.`);
      return;
    }

    const existingIndex = selectedItems.findIndex(i => i.itemId === targetItem.id);
    if (existingIndex >= 0) {
      const updated = [...selectedItems];
      if ((updated[existingIndex].quantity + currentItem.quantity) > targetItem.balance) {
         alert(`Quantidade total solicitada excede o estoque atual (${targetItem.balance}).`);
         return;
      }
      updated[existingIndex].quantity += currentItem.quantity;
      setSelectedItems(updated);
    } else {
      setSelectedItems(prev => [...prev, { itemId: targetItem.id, itemName: targetItem.name, quantity: currentItem.quantity }]);
    }

    // Limpa a busca após adicionar
    setSearchTerm('');
    setCurrentItem({ itemId: '', quantity: 1 });
  };

  const removeItem = (id: string) => {
    setSelectedItems(prev => prev.filter(i => i.itemId !== id));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItems.length === 0) {
      alert("Adicione os itens da sua lista antes de finalizar.");
      return;
    }

    addRequest({
      vtr,
      requesterName: requesterName.toUpperCase(),
      items: selectedItems
    });

    setIsSuccess(true);
    setTimeout(() => navigate('/'), 2500);
  };

  if (isSuccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[75vh] p-6 text-center space-y-8 animate-fade-in">
        <div className="bg-green-500 p-8 rounded-[3rem] text-white shadow-2xl shadow-green-100 animate-bounce">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-24 w-24" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <div className="space-y-4">
          <h2 className="text-4xl font-black text-[#003366]">Pedido Realizado!</h2>
          <p className="text-slate-500 font-bold max-w-sm mx-auto text-lg leading-relaxed">
            Sua solicitação foi enviada para o administrador e está sendo processada.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-4xl mx-auto space-y-8 animate-fade-in-up">
      <div className="bg-white p-6 md:p-14 rounded-[3rem] shadow-2xl border border-slate-50">
        <div className="mb-10 text-center">
           <div className="inline-block bg-orange-50 text-[#FF8C00] px-4 py-1 rounded-full text-[10px] font-black tracking-widest uppercase mb-4">Requisição Operacional</div>
           <h2 className="text-3xl font-black text-[#003366] tracking-tight">Lista de <span className="text-[#FF8C00]">Materiais</span></h2>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Viatura (VTR)</label>
              <select 
                className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] focus:bg-white focus:border-[#003366] outline-none transition-all font-black text-[#003366]"
                value={vtr}
                onChange={e => setVtr(e.target.value)}
                required
              >
                <option value="">Selecione...</option>
                {VEHICLES.map(v => <option key={v} value={v}>VTR {v}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Responsável</label>
              <input 
                type="text" 
                autoComplete="off"
                className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] focus:bg-white focus:border-[#003366] outline-none transition-all font-bold text-slate-700"
                placeholder="Seu nome"
                value={requesterName}
                onChange={e => setRequesterName(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="bg-slate-50 p-6 md:p-10 rounded-[2.5rem] space-y-6 border border-slate-100 relative shadow-inner">
            <div className="absolute -top-4 left-10 bg-white px-4 py-1.5 text-[10px] font-black text-[#FF8C00] uppercase tracking-widest border border-orange-100 rounded-full">Adicionar Materiais</div>

            <div className="flex flex-col md:flex-row gap-4 items-start">
              <div className="flex-[4] w-full space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Buscar por Nome</label>
                <input 
                  type="text"
                  autoComplete="off"
                  placeholder="Ex: Abracadeira, Cabo..."
                  className="w-full p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] focus:border-[#FF8C00] outline-none transition-all font-bold text-slate-700"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />

                {/* Dropdown de resultados da busca */}
                {filteredOptions.length > 0 && (
                  <div className="absolute z-50 left-0 right-0 mt-2 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl overflow-hidden animate-scale-up">
                    {filteredOptions.map(item => (
                      <button
                        key={item.id}
                        type="button"
                        onClick={() => {
                          setCurrentItem({ itemId: item.id, quantity: currentItem.quantity });
                          setSearchTerm(item.name);
                        }}
                        className={`w-full text-left px-5 py-4 hover:bg-orange-50 transition-colors border-b border-slate-50 last:border-0 ${currentItem.itemId === item.id ? 'bg-orange-50 border-l-4 border-l-[#FF8C00]' : ''}`}
                      >
                        <div className="font-bold text-slate-800 text-sm">{item.name}</div>
                        <div className="text-[10px] font-black text-slate-400 uppercase mt-1">Saldo: {item.balance} | ID: {item.id}</div>
                      </button>
                    ))}
                  </div>
                )}
              </div>

              <div className="flex-1 w-full space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center block">Qtd</label>
                <input 
                  type="number" 
                  min="1"
                  className="w-full p-5 bg-white border-2 border-slate-200 rounded-[1.5rem] focus:border-[#FF8C00] outline-none transition-all font-black text-[#FF8C00] text-center text-xl"
                  value={currentItem.quantity}
                  onChange={e => setCurrentItem({...currentItem, quantity: Math.max(1, Number(e.target.value))})}
                />
              </div>

              <button 
                type="button" 
                onClick={() => handleAddItem()} 
                className="w-full md:w-auto mt-6 md:mt-0 bg-[#FF8C00] text-white px-10 py-5 rounded-[1.5rem] font-black text-2xl hover:bg-orange-600 transition-all shadow-xl shadow-orange-100"
              >
                +
              </button>
            </div>

            {selectedItems.length > 0 ? (
              <div className="grid grid-cols-1 gap-3 pt-4">
                <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2 mb-2">Itens Selecionados:</h5>
                {selectedItems.map((item, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm group">
                    <div className="flex items-center gap-4">
                      <div className="bg-orange-50 text-[#FF8C00] w-10 h-10 flex items-center justify-center rounded-xl font-black text-sm">
                        {item.quantity}
                      </div>
                      <div className="font-bold text-slate-700 text-xs md:text-sm">{item.itemName}</div>
                    </div>
                    <button 
                      type="button" 
                      onClick={() => removeItem(item.itemId)} 
                      className="p-2 text-slate-300 hover:text-red-500 transition-all"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-8 border-2 border-dashed border-slate-200 rounded-[2rem] text-slate-400 font-bold text-xs">
                Nenhum item na lista.
              </div>
            )}
          </div>

          <button
            type="submit"
            disabled={isSyncing || selectedItems.length === 0}
            className={`w-full font-black py-6 rounded-[2rem] shadow-2xl transition-all uppercase tracking-widest text-lg ${isSyncing || selectedItems.length === 0 ? 'bg-slate-200 text-slate-400' : 'bg-[#003366] text-white hover:bg-blue-900'}`}
          >
            {isSyncing ? 'Sincronizando...' : 'Enviar Pedido'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default RequestForm;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';
import { GOOGLE_SHEETS_URL, VEHICLES } from '../constants';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
  updateRequestStatus: (id: string, status: 'pending' | 'served') => void;
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
  sheetsUrl: string;
  setSheetsUrl: (url: string) => void;
  fetchFromSheets?: () => Promise<void>;
  lastSync?: number | null;
}

const AdminDashboard: React.FC<Props> = ({ 
  inventory, 
  requests, 
  addTransaction, 
  updateRequestStatus,
  setInventory,
  sheetsUrl,
  setSheetsUrl,
  fetchFromSheets,
  lastSync
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'stock' | 'requests' | 'config'>('stock');
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', balance: 0 });
  const [movement, setMovement] = useState({ itemId: '', quantity: 1, type: 'in' as 'in' | 'out', description: '' });

  useEffect(() => {
    if (sessionStorage.getItem('isAdmin') !== 'true') {
      navigate('/admin/login');
    }
  }, [navigate]);

  // Filtro de segurança para o administrador também
  const cleanInventory = useMemo(() => {
    return inventory.filter(i => {
      const name = String(i.name).trim().toUpperCase();
      const isVtr = VEHICLES.includes(name) || VEHICLES.includes(name.replace('VTR', '').trim());
      const isSystemTag = ['NOVA_SOLICITACAO', 'ATUALIZAR_ESTOQUE_TOTAL', 'ATUALIZACAO_STATUS_PEDIDO', 'MOVIMENTACAO_ESTOQUE'].includes(name);
      return !isVtr && !isSystemTag && name.length > 2;
    });
  }, [inventory]);

  const handleAddStockItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.name.trim()) return;

    const id = Math.floor(10000 + Math.random() * 90000).toString();
    const item: InventoryItem = {
      id,
      name: newItem.name.toUpperCase(),
      balance: newItem.balance,
    };

    setInventory(prev => [item, ...prev]);
    setNewItem({ name: '', balance: 0 });
    setShowAddModal(false);
  };

  const filteredInventory = cleanInventory.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.id.includes(searchTerm)
  );

  const handleExportXLSX = () => {
    if (typeof (window as any).XLSX === 'undefined') {
      alert("Aguarde o carregamento da biblioteca...");
      return;
    }
    const XLSX = (window as any).XLSX;
    const wb = XLSX.utils.book_new();

    const ws1 = XLSX.utils.json_to_sheet(cleanInventory.map(i => ({ ID: i.id, Material: i.name, Saldo: i.balance })));
    XLSX.utils.book_append_sheet(wb, ws1, "Estoque");

    const ws2 = XLSX.utils.json_to_sheet(requests.map(r => ({
      Data: new Date(r.timestamp).toLocaleString(),
      VTR: r.vtr,
      Solicitante: r.requesterName,
      Status: r.status,
      Itens: r.items.map(i => `${i.itemName}(${i.quantity})`).join(', ')
    })));
    XLSX.utils.book_append_sheet(wb, ws2, "Solicitações");

    XLSX.writeFile(wb, `LinhaViva_Relatorio_${new Date().toLocaleDateString().replace(/\//g, '-')}.xlsx`);
  };

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8 animate-fade-in">
      <div className="bg-white rounded-[2rem] p-6 md:p-10 shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="bg-[#003366] p-4 rounded-2xl shadow-lg">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
            </svg>
           </div>
           <div>
             <h2 className="text-3xl font-black text-[#003366]">Painel Administrativo</h2>
             <p className="text-slate-400 font-semibold uppercase text-[10px] tracking-widest mt-1">
               {lastSync ? `Sincronizado: ${new Date(lastSync).toLocaleTimeString()}` : 'Gerenciamento Linha Viva'}
             </p>
           </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          {fetchFromSheets && (
             <button onClick={fetchFromSheets} className="flex-1 md:flex-none bg-[#003366] text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all shadow-lg hover:bg-blue-900">
               Importar da Planilha
             </button>
          )}
          <button onClick={handleExportXLSX} className="flex-1 md:flex-none bg-green-500 hover:bg-green-600 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all shadow-lg">
            XLSX
          </button>
          <button onClick={() => { sessionStorage.removeItem('isAdmin'); navigate('/'); }} className="flex-1 md:flex-none bg-slate-100 text-slate-500 hover:bg-red-50 hover:text-red-500 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all">
            Sair
          </button>
        </div>
      </div>

      <div className="flex bg-slate-100 p-2 rounded-[1.5rem] w-full md:w-fit overflow-x-auto no-scrollbar">
        {[
          { id: 'stock', label: 'Estoque', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
          { id: 'requests', label: 'Pedidos', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2' },
          { id: 'config', label: 'Config', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-8 py-4 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeTab === tab.id ? 'bg-white text-[#003366] shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d={tab.icon} />
            </svg>
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === 'stock' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
              <div className="p-6 md:p-8 bg-slate-50/50 border-b border-slate-100 flex flex-col md:flex-row gap-4 justify-between items-center">
                <div className="relative w-full md:w-72">
                  <input
                    type="text"
                    placeholder="Filtrar materiais..."
                    className="w-full pl-12 pr-4 py-3 bg-white border-2 border-slate-200 rounded-2xl focus:border-[#FF8C00] outline-none transition-all text-sm font-bold text-slate-800"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <button onClick={() => setShowAddModal(true)} className="w-full md:w-auto bg-[#003366] text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-blue-100">+ Adicionar</button>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-slate-50/80 text-[10px] uppercase font-black text-slate-400 tracking-widest">
                    <tr>
                      <th className="px-8 py-5 text-left">Material / ID</th>
                      <th className="px-8 py-5 text-center">Saldo</th>
                      <th className="px-8 py-5 text-right">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredInventory.map(item => (
                      <tr key={item.id} className="hover:bg-slate-50/30 transition-colors group">
                        <td className="px-8 py-6">
                          <div className="font-bold text-slate-800 group-hover:text-[#003366] text-xs md:text-sm">{item.name}</div>
                          <div className="text-[9px] font-black text-slate-400 font-mono mt-1">ID: {item.id}</div>
                        </td>
                        <td className="px-8 py-6 text-center">
                          <span className={`text-xl font-black ${item.balance <= 5 ? 'text-red-500' : 'text-slate-800'}`}>
                            {item.balance}
                          </span>
                        </td>
                        <td className="px-8 py-6 text-right">
                          <span className={`inline-flex px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${item.balance <= 5 ? 'bg-red-100 text-red-600 animate-pulse' : 'bg-green-100 text-green-600'}`}>
                            {item.balance <= 5 ? 'Crítico' : 'Em Dia'}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <div className="lg:col-span-4 h-fit">
            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8 space-y-6 sticky top-24">
              <h3 className="text-xl font-black text-[#003366] uppercase tracking-wide">Lançamento</h3>
              <form onSubmit={(e) => { e.preventDefault(); if (movement.itemId) addTransaction(movement); setMovement({itemId: '', quantity: 1, type: 'in', description: ''}); }} className="space-y-5">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Material</label>
                  <select 
                    className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-bold text-slate-900 text-xs"
                    value={movement.itemId}
                    onChange={e => setMovement({...movement, itemId: e.target.value})}
                    required
                  >
                    <option value="">Escolher...</option>
                    {cleanInventory.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Tipo</label>
                    <select 
                      className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-black text-slate-900"
                      value={movement.type}
                      onChange={e => setMovement({...movement, type: e.target.value as any})}
                    >
                      <option value="in" className="text-green-600">Entrada</option>
                      <option value="out" className="text-red-600">Saída</option>
                    </select>
                  </div>
                  <div className="space-y-1.5">
