import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import { BucketTruckIcon } from './components/Icons';
import { INITIAL_INVENTORY, GOOGLE_SHEETS_URL } from './constants';
import { InventoryItem, MaterialRequest, Transaction } from './types';
import Home from './screens/Home';
import AdminDashboard from './screens/AdminDashboard';
import RequestForm from './screens/RequestForm';
import AdminLogin from './screens/AdminLogin';

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [requests, setRequests] = useState<MaterialRequest[]>(() => {
    const saved = localStorage.getItem('requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [sheetsUrl, setSheetsUrl] = useState<string>(() => {
    const saved = localStorage.getItem('sheetsUrl');
    return saved || GOOGLE_SHEETS_URL;
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<number | null>(null);

  const fetchFromSheets = useCallback(async () => {
    const urlToUse = sheetsUrl || GOOGLE_SHEETS_URL;
    if (!urlToUse) return;

    setIsSyncing(true);
    try {
      const response = await fetch(`${urlToUse}?nocache=${Date.now()}`);
      if (response.ok) {
        const cloudData = await response.json();
        if (Array.isArray(cloudData) && cloudData.length > 0) {
          setInventory(cloudData);
          setLastSync(Date.now());
          localStorage.setItem('inventory', JSON.stringify(cloudData));
        }
      }
    } catch (error) {
      console.error("Linha Viva: Erro ao baixar dados da planilha", error);
    } finally {
      setIsSyncing(false);
    }
  }, [sheetsUrl]);

  const syncToGoogleSheets = async (payload: any, type: string) => {
    const urlToUse = sheetsUrl || GOOGLE_SHEETS_URL;
    if (!urlToUse) return;

    setIsSyncing(true);
    try {
      await fetch(urlToUse, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type, payload })
      });
    } catch (error) {
      console.error("Linha Viva: Falha na sincronização", error);
    } finally {
      // Pequeno delay para o usuário ver o feedback de sincronização
      setTimeout(() => setIsSyncing(false), 1500);
    }
  };

  useEffect(() => {
    fetchFromSheets();
  }, [fetchFromSheets]);

  useEffect(() => {
    localStorage.setItem('requests', JSON.stringify(requests));
  }, [requests]);

  useEffect(() => {
    localStorage.setItem('sheetsUrl', sheetsUrl);
  }, [sheetsUrl]);

  // Função para formatar os dados da transação para a planilha
  const formatTransactionForSheet = (tx: Transaction) => {
    const item = inventory.find(i => i.id === tx.itemId);
    return {
      ID_Transacao: tx.id,
      Data: new Date(tx.timestamp).toLocaleString('pt-BR'),
      ID_Material: tx.itemId,
      Material: item ? item.name : 'Material não encontrado',
      Tipo: tx.type === 'in' ? 'ENTRADA' : 'SAÍDA',
      Quantidade: tx.quantity,
      Descricao: tx.description
    };
  };

  const addItem = async (item: InventoryItem) => {
    const updatedInv = [item, ...inventory];
    setInventory(updatedInv);
    localStorage.setItem('inventory', JSON.stringify(updatedInv));

    // 1. Sincroniza o estoque total
    await syncToGoogleSheets(updatedInv, 'ATUALIZAR_ESTOQUE_TOTAL');

    // 2. Registra a criação em Movimentações
    const logTx: Transaction = {
      id: `ADD-${Math.random().toString(36).substr(2, 5)}`.toUpperCase(),
      itemId: item.id,
      type: 'in',
      quantity: item.balance,
      timestamp: Date.now(),
      description: `CADASTRO INICIAL: ${item.name}`
    };

    await new Promise(r => setTimeout(r, 1200));
    const formattedLog = {
      ID_Transacao: logTx.id,
      Data: new Date(logTx.timestamp).toLocaleString('pt-BR'),
      ID_Material: logTx.itemId,
      Material: item.name,
      Tipo: 'ENTRADA',
      Quantidade: logTx.quantity,
      Descricao: logTx.description
    };
    await syncToGoogleSheets(formattedLog, 'MOVIMENTACAO_ESTOQUE');
  };

  const addTransaction = async (transaction: Omit<Transaction, 'id' | 'timestamp'>) => {
    const fullTx: Transaction = {
      ...transaction,
      id: `TX-${Math.random().toString(36).substr(2, 5)}`.toUpperCase(),
      timestamp: Date.now(),
    };

    const updatedInv = inventory.map(item => {
      if (item.id === transaction.itemId) {
        const delta = transaction.type === 'in' ? transaction.quantity : -transaction.quantity;
        return { ...item, balance: Math.max(0, item.balance + delta) };
      }
      return item;
    });

    setInventory(updatedInv);
    localStorage.setItem('inventory', JSON.stringify(updatedInv));

    // Primeiro envia o saldo atualizado
    await syncToGoogleSheets(updatedInv, 'ATUALIZAR_ESTOQUE_TOTAL');

    // Depois envia a linha de log para a aba de movimentações
    await new Promise(r => setTimeout(r, 1200));
    const formattedTx = formatTransactionForSheet(fullTx);
    await syncToGoogleSheets(formattedTx, 'MOVIMENTACAO_ESTOQUE');
  };

  const addRequest = (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => {
    const newRequest: MaterialRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      status: 'pending',
    };
    setRequests(prev => [newRequest, ...prev]);
    syncToGoogleSheets(newRequest, 'NOVA_SOLICITACAO');
  };

  const updateRequestStatus = async (id: string, status: 'pending' | 'served') => {
    const request = requests.find(r => r.id === id);
    if (!request || request.status === status) return;

    let updatedInv = [...inventory];

    if (status === 'served') {
      setIsSyncing(true);

      // Processa e registra cada item individualmente nas movimentações
      for (const reqItem of request.items) {
        updatedInv = updatedInv.map(invItem => {
          if (invItem.id === reqItem.itemId) {
            return { ...invItem, balance: Math.max(0, invItem.balance - reqItem.quantity) };
          }
          return invItem;
        });

        const txPayload = {
          ID_Transacao: `PED-${request.vtr}-${Math.random().toString(36).substr(2, 4)}`.toUpperCase(),
          Data: new Date().toLocaleString('pt-BR'),
          ID_Material: reqItem.itemId,
          Material: reqItem.itemName,
          Tipo: 'SAÍDA',
          Quantidade: reqItem.quantity,
          Descricao: `SOLICITAÇÃO VTR ${request.vtr} (${request.requesterName})`
        };

        await syncToGoogleSheets(txPayload, 'MOVIMENTACAO_ESTOQUE');
        // Delay para evitar limite de requisições por segundo do Google
        await new Promise(r => setTimeout(r, 1000));
      }

      setInventory(updatedInv);
      localStorage.setItem('inventory', JSON.stringify(updatedInv));
      await syncToGoogleSheets(updatedInv, 'ATUALIZAR_ESTOQUE_TOTAL');
    }

    setRequests(prev => prev.map(req => req.id === id ? { ...req, status } : req));
    syncToGoogleSheets({ id, status }, 'ATUALIZACAO_STATUS_PEDIDO');
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50 font-sans">
        <header className="bg-[#003366] text-white p-4 shadow-xl flex items-center justify-between sticky top-0 z-50">
          <Link to="/" className="flex items-center gap-3 group">
            <BucketTruckIcon className="w-10 h-10 text-white group-hover:text-[#FF8C00] transition-colors" />
            <div>
              <h1 className="text-xl font-bold tracking-tight">Linha Viva</h1>
              <p className="text-[10px] uppercase tracking-widest opacity-80">Itabaiana</p>
            </div>
          </Link>
          <div className="flex items-center gap-4">
            {isSyncing && (
              <div className="flex items-center gap-2 text-[10px] bg-orange-500/20 text-orange-200 px-4 py-2 rounded-full border border-orange-500/30 font-black animate-pulse">
                <span className="w-2 h-2 bg-orange-400 rounded-full animate-ping"></span>
                SINC. CLOUD...
              </div>
            )}
          </div>
        </header>

        <main className="flex-1 overflow-y-auto">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route 
              path="/admin/dashboard" 
              element={
                <AdminDashboard 
                  inventory={inventory} 
                  requests={requests} 
                  addTransaction={addTransaction}
                  addItem={addItem}
                  updateRequestStatus={updateRequestStatus}
                  setInventory={setInventory}
                  sheetsUrl={sheetsUrl}
                  setSheetsUrl={setSheetsUrl}
                  fetchFromSheets={fetchFromSheets}
                  lastSync={lastSync}
                />
              } 
            />
            <Route 
              path="/request" 
              element={<RequestForm inventory={inventory} addRequest={addRequest} isSyncing={isSyncing} />} 
            />
          </Routes>
        </main>

        <footer className="bg-white text-gray-400 text-[10px] p-3 text-center border-t">
          &copy; {new Date().getFullYear()} Linha Viva Itabaiana - Gestão de Materiais
        </footer>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';
import { GOOGLE_SHEETS_URL, VEHICLES } from '../constants';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
  addItem: (item: InventoryItem) => Promise<void>;
  updateRequestStatus: (id: string, status: 'pending' | 'served') => void;
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
  sheetsUrl: string;
  setSheetsUrl: (url: string) => void;
  fetchFromSheets?: () => Promise<void>;
  lastSync?: number | null;
}

const AdminDashboard: React.FC<Props> = ({ 
  inventory, 
  requests, 
  addTransaction, 
  addItem,
  updateRequestStatus,
  setInventory,
  sheetsUrl,
  setSheetsUrl,
  fetchFromSheets,
  lastSync
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'stock' | 'requests' | 'config'>('stock');
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({ id: '', name: '', balance: 0 });
  const [movement, setMovement] = useState({ itemId: '', quantity: 1, type: 'in' as 'in' | 'out', description: '' });

  useEffect(() => {
    if (sessionStorage.getItem('isAdmin') !== 'true') {
      navigate('/admin/login');
    }
  }, [navigate]);

  const cleanInventory = useMemo(() => {
    return inventory.filter(i => {
      const name = String(i.name).trim().toUpperCase();
      const isVtr = VEHICLES.includes(name) || VEHICLES.includes(name.replace('VTR', '').trim());
      const isSystemTag = ['NOVA_SOLICITACAO', 'ATUALIZAR_ESTOQUE_TOTAL', 'ATUALIZACAO_STATUS_PEDIDO', 'MOVIMENTACAO_ESTOQUE'].includes(name);
      return !isVtr && !isSystemTag && name.length > 2;
    });
  }, [inventory]);

  const handleAddStockItem = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.id.trim() || !newItem.name.trim()) {
      alert("Preencha o Código e a Descrição.");
      return;
    }

    try {
      const item: InventoryItem = {
        id: newItem.id.trim(),
        name: newItem.name.toUpperCase().trim(),
        balance: newItem.balance,
      };

      await addItem(item);
      setNewItem({ id: '', name: '', balance: 0 });
      setShowAddModal(false);
      alert('Material cadastrado e sincronizado com a planilha!');
    } catch (err) {
      console.error(err);
      alert('Erro ao cadastrar material. Verifique sua conexão.');
    }
  };

  const handleMovementSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!movement.itemId) {
      alert("Selecione um material.");
      return;
    }

    try {
      await addTransaction({
        itemId: movement.itemId,
        quantity: movement.quantity,
        type: movement.type,
        description: movement.description || (movement.type === 'in' ? 'Entrada manual' : 'Saída manual')
      });
      setMovement({itemId: '', quantity: 1, type: 'in', description: ''});
      alert('Movimentação registrada e enviada para a planilha!');
    } catch (err) {
      console.error(err);
      alert('Falha ao registrar movimentação.');
    }
  };

  const filteredInventory = cleanInventory.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.id.includes(searchTerm)
  );

  const handleExportXLSX = () => {
    if (typeof (window as any).XLSX === 'undefined') {
      alert("Aguarde o carregamento da biblioteca...");
      return;
    }
    const XLSX = (window as any).XLSX;
    const wb = XLSX.utils.book_new();

    const ws1 = XLSX.utils.json_to_sheet(cleanInventory.map(i => ({ ID: i.id, Material: i.name, Saldo: i.balance })));
    XLSX.utils.book_append_sheet(wb, ws1, "Estoque");

    const ws2 = XLSX.utils.json_to_sheet(requests.map(r => ({
      Data: new Date(r.timestamp).toLocaleString(),
      VTR: r.vtr,
      Solicitante: r.requesterName,
      Status: r.status,
      Itens: r.items.map(i => `${i.itemName}(${i.quantity})`).join(', ')
    })));
    XLSX.utils.book_append_sheet(wb, ws2, "Solicitações");

    XLSX.writeFile(wb, `LinhaViva_Relatorio_${new Date().toLocaleDateString().replace(/\//g, '-')}.xlsx`);
  };

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8 animate-fade-in relative">
      {/* Modal de Adição de Material */}
      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#003366]/70 backdrop-blur-md animate-fade-in">
          <div className="bg-white rounded-[3.5rem] p-10 md:p-14 w-full max-w-md shadow-2xl animate-scale-up border-4 border-white flex flex-col">
            <h3 className="text-2xl font-black text-[#003366] mb-10 uppercase tracking-tighter text-center">Novo Material</h3>

            <form onSubmit={handleAddStockItem} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código</label>
                <input 
                  type="text" 
                  autoFocus
                  required
                  placeholder="Ex: 90001"
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-bold text-slate-800"
                  value={newItem.id}
                  onChange={e => setNewItem({...newItem, id: e.target.value})}
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição Completa</label>
                <input 
                  type="text" 
                  required
                  placeholder="Nome do material"
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-bold text-slate-800 uppercase"
                  value={newItem.name}
                  onChange={e => setNewItem({...newItem, name: e.target.value})}
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Saldo Inicial</label>
                <input 
                  type="number" 
                  required
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] focus:bg-white focus:border-[#FF8C00] outline-none transition-all font-black text-[#FF8C00] text-3xl"
                  value={newItem.balance}
                  onChange={e => setNewItem({...newItem, balance: Number(e.target.value)})}
                />
              </div>

              <div className="flex flex-col sm:flex-row gap-4 pt-6">
                <button 
                  type="button" 
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 bg-slate-100 text-slate-500 font-black py-5 rounded-[1.5rem] uppercase tracking-widest text-xs hover:bg-slate-200 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 bg-[#003366] text-white font-black py-5 rounded-[1.5rem] shadow-2xl shadow-blue-200 uppercase tracking-widest text-xs hover:bg-blue-900 transition-all active:scale-95"
                >
                  Cadastrar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Cabeçalho do Dashboard */}
      <div className="bg-white rounded-[2.5rem] p-6 md:p-10 shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="bg-[#003366] p-4 rounded-2xl shadow-lg">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
            </svg>
           </div>
           <div>
             <h2 className="text-3xl font-black text-[#003366]">Painel Administrativo</h2>
             <p className="text-slate-400 font-semibold uppercase text-[10px] tracking-widest mt-1">
               {lastSync ? `Sincronizado: ${new Date(lastSync).toLocaleTimeString()}` : 'Gerenciamento Linha Viva'}
             </p>
           </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          {fetchFromSheets && (
             <button onClick={fetchFromSheets} className="flex-1 md:flex-none bg-[#003366] text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all shadow-lg hover:bg-blue-900 active:scale-95">
               Importar Nuvem
             </button>
          )}
          <button onClick={handleExportXLSX} className="flex-1 md:flex-none bg-green-500 hover:bg-green-600 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all shadow-lg active:scale-95">
            Relatório XLSX
          </button>
          <button onClick={() => { sessionStorage.removeItem('isAdmin'); navigate('/'); }} className="flex-1 md:flex-none bg-slate-100 text-slate-500 hover:bg-red-50 hover:text-red-500 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-wide transition-all active:scale-95">
            Sair
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-slate-100 p-2 rounded-[1.5rem] w-full md:w-fit overflow-x-auto no-scrollbar">
        {[
          { id: 'stock', label: 'Estoque', icon: 'M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4' },
          { id: 'requests', label: 'Pedidos', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2' },
