              <div key={req.id} className={`group bg-white p-6 rounded-[2.5rem] shadow-sm border-2 transition-all hover:shadow-xl ${req.status === 'served' ? 'border-green-100 opacity-60' : 'border-slate-50 hover:border-[#FF8C00]'}`}>
