O erro de não registrar na planilha ocorre quase sempre devido a um desencontro entre as **chaves do JSON** enviadas pelo frontend e o **código do Google Apps Script** que recebe esses dados. Além disso, o Google Apps Script exige que o retorno de uma função `doPost` seja um `TextOutput` específico para evitar erros de CORS no navegador.

Abaixo, apresento a correção completa do `App.tsx` e, **muito importante**, o código do **Google Apps Script** que você deve colar no seu Editor de Script da Planilha para que tudo funcione.

### 1. Código do Google Apps Script (Copie e cole na sua planilha)
*No menu da sua planilha, vá em: Extensões > Apps Script. Apague tudo e cole isso:*

```javascript
function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var res;

  try {
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;

    if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = ss.getSheetByName('Estoque');
      if(!sheet) sheet = ss.insertSheet('Estoque');
      sheet.clear();
      sheet.appendRow(['ID', 'MATERIAL', 'SALDO']);
      payload.forEach(function(item) {
        sheet.appendRow([item.id, item.name, item.balance]);
      });
    } 

    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = ss.getSheetByName('Movimentacoes');
      if(!sheet) sheet = ss.insertSheet('Movimentacoes');
      if(sheet.getLastRow() === 0) sheet.appendRow(['ID_TRANSACAO', 'DATA', 'ID_MATERIAL', 'MATERIAL', 'MOVIMENTACAO', 'QUANTIDADE', 'OBSERVACAO']);
      sheet.appendRow([
        payload.ID_TRANSACAO, 
        payload.DATA, 
        payload.ID_MATERIAL, 
        payload.MATERIAL, 
        payload.MOVIMENTACAO, 
        payload.QUANTIDADE, 
        payload.OBSERVACAO
      ]);
    }

    else if (type === 'NOVA_SOLICITACAO') {
      var sheet = ss.getSheetByName('Solicitacoes');
      if(!sheet) sheet = ss.insertSheet('Solicitacoes');
      if(sheet.getLastRow() === 0) sheet.appendRow(['ID_PEDIDO', 'DATA', 'VTR', 'SOLICITANTE', 'ITENS', 'STATUS']);
      sheet.appendRow([
        payload.ID_PEDIDO, 
        payload.DATA, 
        payload.VTR, 
        payload.SOLICITANTE, 
        payload.ITENS, 
        payload.STATUS
      ]);
    }

    else if (type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName('Solicitacoes');
      var rows = sheet.getDataRange().getValues();
      for (var i = 1; i < rows.length; i++) {
        if (rows[i][0] == payload.ID_PEDIDO) {
          sheet.getCell(i + 1, 6).setValue(payload.STATUS); // Coluna 6 é o Status
          break;
        }
      }
    }

    res = { status: 'success' };
  } catch (err) {
    res = { status: 'error', message: err.toString() };
  }

  return ContentService.createTextOutput(JSON.stringify(res)).setMimeType(ContentService.MimeType.JSON);
}

function doGet() {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName('Estoque');
  var data = sheet.getDataRange().getValues();
  var result = [];
  for (var i = 1; i < data.length; i++) {
    result.push({ id: String(data[i][0]), name: data[i][1], balance: Number(data[i][2]) });
  }
  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}
```

