payload.text:
Para resolver o problema de comunicação e garantir que tanto as **Solicitações** quanto as **Movimentações** sejam registradas corretamente na planilha, identifiquei que o principal ponto de falha costuma ser a forma como o navegador lida com o redirecionamento do Google Apps Script e o formato do cabeçalho.

Abaixo estão as correções detalhadas.

### 1. Novo Código para o Google Apps Script (Servidor)
**Importante:** No Editor do Apps Script da sua planilha, substitua todo o código existente por este. Ele foi otimizado com `LockService` para evitar que uma gravação atropele a outra quando houver muitos itens.

```javascript
/**
 * GOOGLE APPS SCRIPT - LINHA VIVA ITABAIANA
 * Configure como: Implantação > Nova Implantação > App da Web
 * Executar como: Eu
 * Quem pode acessar: Qualquer um
 */

function doPost(e) {
  var lock = LockService.getScriptLock();
  try {
    lock.waitLock(10000); // Aguarda até 10 segundos para obter o bloqueio de escrita

    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;
    var res = { status: 'success' };

    if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = ss.getSheetByName('Estoque') || ss.insertSheet('Estoque');
      sheet.clear();
      sheet.appendRow(['ID', 'MATERIAL', 'SALDO']);
      if (Array.isArray(payload)) {
        payload.forEach(function(item) {
          sheet.appendRow([item.id, item.name, item.balance]);
        });
      }
    } 

    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = ss.getSheetByName('Movimentacoes') || ss.insertSheet('Movimentacoes');
      if(sheet.getLastRow() === 0) {
        sheet.appendRow(['ID_TRANSACAO', 'DATA', 'ID_MATERIAL', 'MATERIAL', 'MOVIMENTACAO', 'QUANTIDADE', 'OBSERVACAO']);
      }
      sheet.appendRow([
        payload.ID_TRANSACAO, 
        payload.DATA, 
        payload.ID_MATERIAL, 
        payload.MATERIAL, 
        payload.MOVIMENTACAO, 
        payload.QUANTIDADE, 
        payload.OBSERVACAO
      ]);
    }

    else if (type === 'NOVA_SOLICITACAO') {
      var sheet = ss.getSheetByName('Solicitacoes') || ss.insertSheet('Solicitacoes');
      if(sheet.getLastRow() === 0) {
        sheet.appendRow(['ID_PEDIDO', 'DATA', 'VTR', 'SOLICITANTE', 'ITENS', 'STATUS']);
      }
      sheet.appendRow([
        payload.ID_PEDIDO, 
        payload.DATA, 
        payload.VTR, 
        payload.SOLICITANTE, 
        payload.ITENS, 
        payload.STATUS
      ]);
    }

    else if (type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName('Solicitacoes');
      if (sheet) {
        var rows = sheet.getDataRange().getValues();
        for (var i = 1; i < rows.length; i++) {
          if (rows[i][0] == payload.ID_PEDIDO) {
            sheet.getRange(i + 1, 6).setValue(payload.STATUS);
            break;
          }
        }
      }
    }

    return ContentService.createTextOutput(JSON.stringify(res)).setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function doGet() {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName('Estoque');
  if (!sheet) return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);

  var data = sheet.getDataRange().getValues();
  var result = [];
  for (var i = 1; i < data.length; i++) {
    result.push({ 
      id: String(data[i][0]), 
      name: String(data[i][1]), 
      balance: Number(data[i][2]) 
    });
  }
  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}
```

### 2. Atualizações no Aplicativo (Frontend)

Vou atualizar o `App.tsx` para tornar a função de sincronização mais resiliente a erros de rede e garantir que os dados cheguem no formato exato que o script espera.

