                  onClick={() => setSheetsUrl(GOOGLE_SHEETS_URL)}
                  className="w-full bg-slate-100 text-[#003366] px-6 py-4 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 transition-all active:scale-95"
                >
                  Restaurar Original
                </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

payload.text:
Para implementar a separação de estoques por região (Itabaiana e Dores), precisamos ajustar a estrutura de dados tanto no aplicativo quanto na lógica da planilha Google.

### Especificações das Alterações

1.  **Estrutura de Dados (`types.ts`)**: Alteração do `InventoryItem` para conter `balanceItabaiana` e `balanceDores` em vez de um saldo único.
2.  **Interface do Usuário (Admin)**: 
    *   A tabela de estoque passará a exibir duas colunas de saldo.
    *   O formulário de movimentação manual ganhará um seletor para escolher qual depósito ajustar.
3.  **Lógica de Atendimento**: Ao atender um pedido de "Dores", o sistema subtrairá automaticamente do saldo de Dores. O mesmo para Itabaiana.
4.  **Sincronização**: O payload enviado para o Google Sheets conterá os dois saldos separadamente.

### 1. Atualização do Google Apps Script (Servidor)
*Você deve copiar e colar este código no seu Editor de Script da Planilha para que a nova estrutura funcione:*

```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  try {
    lock.waitLock(10000);
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;

    if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = ss.getSheetByName('Estoque') || ss.insertSheet('Estoque');
      sheet.clear();
      sheet.appendRow(['ID', 'MATERIAL', 'SALDO_ITABAIANA', 'SALDO_DORES']);
      if (Array.isArray(payload)) {
        payload.forEach(function(item) {
          sheet.appendRow([item.id, item.name, item.balanceItabaiana || 0, item.balanceDores || 0]);
        });
      }
    } 
    // ... manter as outras lógicas de MOVIMENTACAO_ESTOQUE e NOVA_SOLICITACAO ...
    return ContentService.createTextOutput(JSON.stringify({status: 'success'})).setMimeType(ContentService.MimeType.JSON);
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({status: 'error', message: err.toString()})).setMimeType(ContentService.MimeType.JSON);
  } finally { lock.releaseLock(); }
}

function doGet() {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName('Estoque');
  if (!sheet) return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);
  var data = sheet.getDataRange().getValues();
  var result = [];
  for (var i = 1; i < data.length; i++) {
    result.push({ 
      id: String(data[i][0]), 
      name: String(data[i][1]), 
      balanceItabaiana: Number(data[i][2]) || 0,
      balanceDores: Number(data[i][3]) || 0
    });
  }
  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}
```

### 2. Alterações no Código do App

