import React, { useState, useMemo, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { VEHICLES } from '../constants';
import { InventoryItem, RequestedItem, MaterialRequest } from '../types';

interface Props {
  inventory: InventoryItem[];
  addRequest: (request: Omit<MaterialRequest, 'id' | 'timestamp' | 'status'>) => void;
  isSyncing: boolean;
}

const RequestForm: React.FC<Props> = ({ inventory, addRequest, isSyncing }) => {
  const navigate = useNavigate();
  const [vtr, setVtr] = useState('');
  const [region, setRegion] = useState<'ITABAIANA' | 'DORES'>('ITABAIANA');
  const [requesterName, setRequesterName] = useState('');
  const [selectedItems, setSelectedItems] = useState<RequestedItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [currentItem, setCurrentItem] = useState({ itemId: '', quantity: 1 });
  const [isSuccess, setIsSuccess] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsDropdownOpen(false);
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const availableItems = useMemo(() => {
    return inventory.filter(i => {
      const balance = region === 'ITABAIANA' ? i.balanceItabaiana : i.balanceDores;
      return balance > 0 && i.name.length > 3;
    });
  }, [inventory, region]);

  const filteredOptions = useMemo(() => {
    const search = searchTerm.toLowerCase().trim();
    if (!search) return availableItems.slice(0, 50);
    return availableItems.filter(i => i.name.toLowerCase().includes(search) || i.id.includes(search)).slice(0, 50);
  }, [searchTerm, availableItems]);

  const handleAddItem = (item?: InventoryItem) => {
    const target = item || availableItems.find(i => i.id === currentItem.itemId);
    if (!target) return;

    const currentBalance = region === 'ITABAIANA' ? target.balanceItabaiana : target.balanceDores;
    if (currentItem.quantity > currentBalance) {
      alert(`Saldo insuficiente em ${region}. Disponível: ${currentBalance}`);
      return;
    }

    const existing = selectedItems.find(i => i.itemId === target.id);
    if (existing) {
      if ((existing.quantity + currentItem.quantity) > currentBalance) {
        alert("Quantidade total excede o estoque da regional.");
        return;
      }
      setSelectedItems(prev => prev.map(i => i.itemId === target.id ? { ...i, quantity: i.quantity + currentItem.quantity } : i));
    } else {
      setSelectedItems(prev => [...prev, { itemId: target.id, itemName: target.name, quantity: currentItem.quantity }]);
    }
    setSearchTerm('');
    setCurrentItem({ itemId: '', quantity: 1 });
    setIsDropdownOpen(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!vtr || selectedItems.length === 0) return;
    addRequest({ vtr, region, requesterName: requesterName.toUpperCase() || 'COLABORADOR', items: selectedItems });
    setIsSuccess(true);
    setTimeout(() => navigate('/'), 2500);
  };

  if (isSuccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[75vh] p-6 text-center animate-fade-in">
        <div className="bg-green-500 p-8 rounded-[3rem] text-white shadow-2xl animate-bounce mb-8">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-3xl font-black text-[#003366]">Pedido Enviado!</h2>
        <p className="text-slate-400 font-bold uppercase text-[10px] mt-2">Retirada em: {region}</p>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-4xl mx-auto animate-fade-in-up">
      <div className="bg-white p-6 md:p-12 rounded-[3rem] shadow-2xl border border-slate-50">
        <h2 className="text-3xl font-black text-[#003366] text-center mb-10">Solicitar <span className="text-[#FF8C00]">Material</span></h2>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Retirar em:</label>
              <div className="flex bg-slate-100 p-1 rounded-2xl">
                <button type="button" onClick={() => { setRegion('ITABAIANA'); setSelectedItems([]); }} className={`flex-1 py-4 rounded-xl font-black text-[10px] uppercase transition-all ${region === 'ITABAIANA' ? 'bg-white text-[#003366] shadow-sm' : 'text-slate-400'}`}>Itabaiana</button>
                <button type="button" onClick={() => { setRegion('DORES'); setSelectedItems([]); }} className={`flex-1 py-4 rounded-xl font-black text-[10px] uppercase transition-all ${region === 'DORES' ? 'bg-white text-[#003366] shadow-sm' : 'text-slate-400'}`}>Dores</button>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">VTR / Viatura</label>
              <select className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-[#003366] outline-none font-black text-[#003366] transition-colors" value={vtr} onChange={e => setVtr(e.target.value)} required>
                <option value="" className="text-slate-400">Selecione...</option>
                {VEHICLES.map(v => <option key={v} value={v} className="text-slate-800 font-bold">VTR {v}</option>)}
              </select>
            </div>

            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Solicitante</label>
              <input type="text" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none font-bold uppercase text-slate-800 placeholder:text-slate-300 focus:border-[#003366] transition-colors" placeholder="Nome Completo" value={requesterName} onChange={e => setRequesterName(e.target.value)} required />
            </div>
          </div>

          <div className="bg-slate-50 p-6 md:p-10 rounded-[2.5rem] space-y-6 relative shadow-inner">
            <div className="absolute -top-3 left-10 bg-white px-4 py-1 text-[9px] font-black text-[#FF8C00] uppercase tracking-widest border rounded-full">Itens em {region}</div>

            <div className="flex flex-col md:flex-row gap-4 items-end" ref={dropdownRef}>
              <div className="flex-1 space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Buscar Material</label>
                <input 
                  type="text" 
                  placeholder="Ex: Abracadeira..." 
                  className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl outline-none font-bold text-slate-800 placeholder:text-slate-400 focus:border-[#FF8C00] transition-colors" 
                  value={searchTerm} 
                  onFocus={() => setIsDropdownOpen(true)} 
                  onChange={e => { setSearchTerm(e.target.value); setIsDropdownOpen(true); }} 
                />

                {isDropdownOpen && (
                  <div className="absolute z-50 left-0 right-0 mt-2 bg-white border-2 border-slate-200 rounded-2xl shadow-2xl max-h-64 overflow-y-auto overflow-x-hidden animate-scale-up">
                    {filteredOptions.length === 0 ? (
                      <div className="p-4 text-center text-xs font-bold text-slate-400 uppercase">Nenhum material encontrado</div>
                    ) : (
                      filteredOptions.map(item => (
                        <button 
                          key={item.id} 
                          type="button" 
                          onClick={() => { setCurrentItem({ ...currentItem, itemId: item.id }); setSearchTerm(item.name); setIsDropdownOpen(false); }} 
                          className="w-full text-left px-5 py-4 hover:bg-orange-50 border-b border-slate-50 last:border-0 group transition-colors"
                        >
                          <div className="text-[11px] font-black uppercase truncate text-slate-900 group-hover:text-[#FF8C00]">{item.name}</div>
                          <div className="flex justify-between items-center mt-1">
                            <span className="text-[9px] text-slate-500 font-mono font-bold tracking-tighter">CÓDIGO: {item.id}</span>
                            <span className="text-[10px] font-black text-[#FF8C00] bg-orange-100/50 px-2 py-0.5 rounded-md">ESTOQUE: {region === 'ITABAIANA' ? item.balanceItabaiana : item.balanceDores}</span>
                          </div>
                        </button>
                      ))
                    )}
                  </div>
                )}
              </div>
              <div className="w-full md:w-24 space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center block">Qtd</label>
                <input 
                  type="number" 
                  min="1" 
                  className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl font-black text-center text-xl text-slate-800 outline-none focus:border-[#FF8C00]" 
                  value={currentItem.quantity} 
                  onChange={e => setCurrentItem({...currentItem, quantity: Math.max(1, Number(e.target.value))})} 
                />
              </div>
              <button 
                type="button" 
                onClick={() => handleAddItem()} 
                className="w-full md:w-auto bg-[#FF8C00] text-white px-8 py-4 rounded-2xl font-black text-2xl shadow-lg shadow-orange-100 hover:bg-orange-600 transition-all active:scale-95 flex items-center justify-center"
              >
                +
              </button>
            </div>

            <div className="space-y-3 pt-4 border-t border-slate-200">
              {selectedItems.length > 0 && <h4 className="text-[9px] font-black text-slate-400 uppercase mb-2">Materiais Selecionados:</h4>}
              {selectedItems.map((item, idx) => (
                <div key={idx} className="flex justify-between items-center bg-white p-4 rounded-2xl border border-slate-100 shadow-sm animate-scale-up">
                  <span className="text-xs font-black text-slate-700 uppercase leading-tight max-w-[70%]">{item.itemName}</span>
                  <div className="flex items-center gap-4">
                    <span className="bg-orange-50 text-[#FF8C00] px-3 py-1 rounded-lg font-black text-sm border border-orange-100">x{item.quantity}</span>
                    <button type="button" onClick={() => setSelectedItems(prev => prev.filter(i => i.itemId !== item.itemId))} className="text-slate-300 hover:text-red-500 transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <button 
            type="submit" 
            disabled={isSyncing || selectedItems.length === 0} 
            className="w-full bg-[#003366] text-white py-6 rounded-3xl font-black text-lg uppercase shadow-2xl shadow-blue-100 disabled:bg-slate-200 disabled:text-slate-400 transition-all active:scale-95 hover:bg-blue-900"
          >
            {isSyncing ? 'Sincronizando...' : 'Finalizar Pedido'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default RequestForm;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';
import { GOOGLE_SHEETS_URL, VEHICLES, CRITICAL_THRESHOLD } from '../constants';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
  addItem: (item: InventoryItem) => Promise<void>;
  updateRequestStatus: (id: string, status: 'pending' | 'served') => void;
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
  sheetsUrl: string;
  setSheetsUrl: (url: string) => void;
  fetchFromSheets?: () => Promise<void>;
  lastSync?: number | null;
}

const AdminDashboard: React.FC<Props> = ({ 
  inventory, requests, addTransaction, addItem, updateRequestStatus, sheetsUrl, setSheetsUrl, fetchFromSheets, lastSync
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'stock' | 'requests' | 'config'>('stock');
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showMovementModal, setShowMovementModal] = useState(false);
  const [newItem, setNewItem] = useState({ id: '', name: '', balanceItabaiana: 0, balanceDores: 0 });
  const [movement, setMovement] = useState({ itemId: '', quantity: 1, type: 'in' as 'in' | 'out', region: 'ITABAIANA' as 'ITABAIANA' | 'DORES', description: '' });

  useEffect(() => {
    if (sessionStorage.getItem('isAdmin') !== 'true') navigate('/admin/login');
  }, [navigate]);

  const filteredInventory = useMemo(() => {
    return inventory.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) || item.id.includes(searchTerm)
    );
  }, [inventory, searchTerm]);

  const handleAddStockItem = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.id.trim() || !newItem.name.trim()) return;
    await addItem({ ...newItem, name: newItem.name.toUpperCase() });
    setShowAddModal(false);
    setNewItem({ id: '', name: '', balanceItabaiana: 0, balanceDores: 0 });
  };

  const handleMovementSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!movement.itemId) return;
    addTransaction({
      itemId: movement.itemId,
      quantity: movement.quantity,
      type: movement.type,
      region: movement.region,
      description: movement.description || (movement.type === 'in' ? 'Entrada manual' : 'Saída manual')
    });
    setMovement({ itemId: '', quantity: 1, type: 'in', region: 'ITABAIANA', description: '' });
    setShowMovementModal(false);
  };

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-6 animate-fade-in pb-20">

      {/* Modal: Novo Material */}
      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#003366]/80 backdrop-blur-sm">
          <div className="bg-white rounded-[2rem] p-8 w-full max-w-md shadow-2xl animate-scale-up border border-slate-100">
            <h3 className="text-xl font-black text-[#003366] mb-6 uppercase text-center">Novo Material</h3>
            <form onSubmit={handleAddStockItem} className="space-y-4">
              <input type="text" placeholder="Código (ID)" className="w-full p-4 bg-slate-50 border-2 rounded-xl outline-none font-bold text-slate-800 placeholder:text-slate-300" value={newItem.id} onChange={e => setNewItem({...newItem, id: e.target.value})} required />
              <input type="text" placeholder="Descrição do Material" className="w-full p-4 bg-slate-50 border-2 rounded-xl outline-none font-bold uppercase text-slate-800 placeholder:text-slate-300" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} required />
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase">Qtd Itabaiana</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border-2 rounded-xl font-black text-slate-800" value={newItem.balanceItabaiana} onChange={e => setNewItem({...newItem, balanceItabaiana: Number(e.target.value)})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase">Qtd Dores</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border-2 rounded-xl font-black text-slate-800" value={newItem.balanceDores} onChange={e => setNewItem({...newItem, balanceDores: Number(e.target.value)})} />
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 bg-slate-100 py-4 rounded-xl font-black text-xs text-slate-500 uppercase">Cancelar</button>
                <button type="submit" className="flex-1 bg-[#003366] py-4 rounded-xl font-black text-xs text-white uppercase shadow-lg">Cadastrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal: Movimentar Estoque */}
      {showMovementModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#003366]/80 backdrop-blur-sm">
          <div className="bg-white rounded-[2rem] p-8 w-full max-w-md shadow-2xl animate-scale-up border border-slate-100">
            <h3 className="text-xl font-black text-[#003366] mb-6 uppercase text-center">Movimentar Estoque</h3>
            <form onSubmit={handleMovementSubmit} className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1 mb-1 block">Material</label>
                <select className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none font-bold text-xs text-slate-800 focus:border-[#FF8C00] transition-colors" value={movement.itemId} onChange={e => setMovement({...movement, itemId: e.target.value})} required>
                  <option value="" className="text-slate-400">Selecione o Material</option>
                  {inventory.map(i => <option key={i.id} value={i.id} className="text-slate-800">{i.name}</option>)}
                </select>
              </div>

              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1 mb-1 block">Regional</label>
                <select className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none font-black text-xs text-[#FF8C00] focus:border-[#FF8C00] transition-colors" value={movement.region} onChange={e => setMovement({...movement, region: e.target.value as any})}>
                  <option value="ITABAIANA">DEPOSITO ITABAIANA</option>
                  <option value="DORES">DEPOSITO DORES</option>
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 mb-1 block">Tipo</label>
                  <select className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none font-black text-xs text-slate-800 focus:border-[#FF8C00] transition-colors" value={movement.type} onChange={e => setMovement({...movement, type: e.target.value as any})}>
                    <option value="in">ENTRADA</option>
                    <option value="out">SAÍDA</option>
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 mb-1 block">Qtd</label>
                  <input type="number" min="1" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none font-black text-lg text-center text-slate-800 focus:border-[#FF8C00] transition-colors" value={movement.quantity} onChange={e => setMovement({...movement, quantity: Math.max(1, Number(e.target.value))})} />
                </div>
              </div>

              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1 mb-1 block">Observação</label>
                <input type="text" placeholder="EX: REPOSIÇÃO DE FROTAS" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none font-bold text-xs uppercase text-slate-800 placeholder:text-slate-300 focus:border-[#FF8C00] transition-colors" value={movement.description} onChange={e => setMovement({...movement, description: e.target.value})} />
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowMovementModal(false)} className="flex-1 bg-slate-100 py-4 rounded-xl font-black text-xs text-slate-500 uppercase">Cancelar</button>
                <button type="submit" className="flex-1 bg-[#FF8C00] py-4 rounded-xl font-black text-xs text-white uppercase shadow-lg shadow-orange-100">Confirmar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2rem] p-6 md:p-10 shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-4">
          <div className="bg-[#003366] p-3 rounded-2xl shadow-lg text-white">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
          </div>
          <div>
            <h2 className="text-2xl font-black text-[#003366]">Painel Administrativo</h2>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{lastSync ? `Sincronizado: ${new Date(lastSync).toLocaleTimeString()}` : 'Aguardando sincronização...'}</p>
          </div>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          {fetchFromSheets && <button onClick={fetchFromSheets} className="flex-1 md:px-6 py-3 bg-[#003366] text-white rounded-xl font-black text-[10px] uppercase shadow-md">Atualizar</button>}
          <button onClick={() => { sessionStorage.removeItem('isAdmin'); navigate('/'); }} className="flex-1 md:px-6 py-3 bg-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase">Sair</button>
        </div>
      </div>

      <div className="flex bg-slate-100 p-1.5 rounded-2xl">
        {['stock', 'requests', 'config'].map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-3.5 rounded-xl font-black text-xs uppercase transition-all ${activeTab === tab ? 'bg-white text-[#003366] shadow-sm' : 'text-slate-400'}`}>
            {tab === 'stock' ? 'Depósitos' : tab === 'requests' ? 'Pedidos' : 'Config'}
          </button>
        ))}
      </div>

      {activeTab === 'stock' && (
        <div className="space-y-6">
          <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-6 bg-slate-50 border-b flex flex-col md:flex-row gap-4 justify-between items-center">
              <input type="text" placeholder="Pesquisar material..." className="w-full md:w-64 p-3 bg-white border-2 rounded-xl outline-none font-bold text-sm text-slate-800" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
              <div className="flex gap-3 w-full md:w-auto">
                <button onClick={() => setShowAddModal(true)} className="flex-1 md:flex-none bg-[#003366] text-white px-6 py-3.5 rounded-xl font-black text-[10px] uppercase shadow-lg">+ Novo Material</button>
                <button onClick={() => setShowMovementModal(true)} className="flex-1 md:flex-none bg-[#FF8C00] text-white px-6 py-3.5 rounded-xl font-black text-[10px] uppercase shadow-lg shadow-orange-100">Movimentar Estoque</button>
              </div>
            </div>
            <div className="overflow-x-auto no-scrollbar">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <tr>
                    <th className="px-8 py-5">Material</th>
                    <th className="px-4 py-5 text-center">Itabaiana</th>
                    <th className="px-4 py-5 text-center">Dores</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 font-bold text-slate-700">
                  {filteredInventory.map(item => (
                    <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-8 py-5">
                        <div className="text-xs uppercase leading-tight">{item.name}</div>
                        <div className="text-[9px] text-slate-300 font-mono mt-1">ID: {item.id}</div>
                      </td>
                      <td className="px-4 py-5 text-center">
                        <span className={`text-lg font-black ${item.balanceItabaiana <= CRITICAL_THRESHOLD ? 'text-red-500' : 'text-slate-800'}`}>{item.balanceItabaiana}</span>
                      </td>
                      <td className="px-4 py-5 text-center">
                        <span className={`text-lg font-black ${item.balanceDores <= CRITICAL_THRESHOLD ? 'text-red-500' : 'text-slate-800'}`}>{item.balanceDores}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'requests' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {requests.length === 0 ? (
            <div className="col-span-full py-20 text-center font-bold text-slate-300 uppercase">Nenhum pedido pendente</div>
          ) : (
            requests.map(req => (
              <div key={req.id} className={`bg-white p-6 rounded-3xl shadow-sm border-2 ${req.status === 'served' ? 'border-green-100 opacity-60' : 'border-slate-50'}`}>
                <div className="flex justify-between items-center mb-4">
                  <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase text-white ${req.region === 'ITABAIANA' ? 'bg-[#003366]' : 'bg-[#FF8C00]'}`}>{req.region}</span>
                  <span className="text-[9px] font-black text-slate-300 uppercase">VTR {req.vtr}</span>
                </div>
                <h4 className="font-black text-[#003366] text-lg mb-4 truncate">{req.requesterName}</h4>
                <div className="space-y-2 mb-6 max-h-40 overflow-y-auto no-scrollbar">
                  {req.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between bg-slate-50 p-2.5 rounded-xl text-[10px] font-bold uppercase text-slate-700">
                      <span className="truncate mr-2">{item.itemName}</span>
                      <span className="text-[#FF8C00]">x{item.quantity}</span>
                    </div>
                  ))}
                </div>
                {req.status === 'pending' ? (
                  <button onClick={() => updateRequestStatus(req.id, 'served')} className="w-full bg-green-500 text-white py-4 rounded-xl font-black text-xs uppercase shadow-md">Atender</button>
                ) : (
                  <div className="w-full bg-slate-100 text-slate-400 py-4 rounded-xl font-black text-xs uppercase text-center">Atendido</div>
                )}
              </div>
            ))
          )}
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-xl mx-auto bg-white rounded-[2rem] p-10 shadow-sm border border-slate-100 space-y-6">
          <h3 className="text-xl font-black text-[#003366] uppercase">Configuração da Nuvem</h3>
          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 uppercase">Google Script URL</label>
            <input type="text" className="w-full p-4 bg-slate-50 border-2 rounded-xl outline-none font-bold text-[10px] text-slate-600" value={sheetsUrl} onChange={e => setSheetsUrl(e.target.value)} />
            <button onClick={() => setSheetsUrl(GOOGLE_SHEETS_URL)} className="w-full py-4 text-[#003366] font-black text-[10px] uppercase">Resetar URL</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { InventoryItem, MaterialRequest, Transaction } from '../types';
import { GOOGLE_SHEETS_URL, VEHICLES, CRITICAL_THRESHOLD } from '../constants';

interface Props {
  inventory: InventoryItem[];
  requests: MaterialRequest[];
  addTransaction: (tx: Omit<Transaction, 'id' | 'timestamp'>) => void;
