Para que o sistema registre os dados corretamente, o seu código no **Google Apps Script** precisa estar preparado para receber o formato de objeto que o App envia.

Abaixo está o código completo e revisado que você deve copiar e colar no seu editor do Apps Script (**Extensões > Apps Script**).

### Código para o Google Apps Script (`Código.gs`)

```javascript
/**
 * SISTEMA LINHA VIVA - GESTÃO REGIONAL
 * Versão: 2.5 (Resiliência de Dados)
 */

function doGet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("ESTOQUE") || ss.insertSheet("ESTOQUE");

  // Se a planilha estiver vazia, cria os cabeçalhos
  if (sheet.getLastRow() === 0) {
    sheet.appendRow(["ID_MATERIAL", "MATERIAL", "SALDO_ITABAIANA", "SALDO_DORES"]);
  }

  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  const json = data.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.getActiveSpreadsheet();

    switch (data.type) {
      case 'ATUALIZAR_ESTOQUE_TOTAL':
        atualizarEstoqueTotal(ss, data.payload);
        break;

      case 'MOVIMENTACAO_ESTOQUE':
        registrarMovimentacao(ss, data.payload);
        break;

      case 'NOVA_SOLICITACAO':
        registrarPedido(ss, data.payload);
        break;

      case 'ATUALIZACAO_STATUS_PEDIDO':
        atualizarStatusPedido(ss, data.payload);
        break;
    }

    return ContentService.createTextOutput(JSON.stringify({ status: "success" }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// 1. Atualiza a planilha de ESTOQUE completa
function atualizarEstoqueTotal(ss, items) {
  const sheet = ss.getSheetByName("ESTOQUE") || ss.insertSheet("ESTOQUE");
  sheet.clear();
  sheet.appendRow(["ID_MATERIAL", "MATERIAL", "SALDO_ITABAIANA", "SALDO_DORES"]);

  if (items && items.length > 0) {
    const rows = items.map(item => [
      item.id,
      item.name.toUpperCase(),
      item.balanceItabaiana,
      item.balanceDores
    ]);
    sheet.getRange(2, 1, rows.length, 4).setValues(rows);
  }
}

// 2. Registra log na planilha de MOVIMENTACOES
function registrarMovimentacao(ss, log) {
  const sheet = ss.getSheetByName("MOVIMENTACOES") || ss.insertSheet("MOVIMENTACOES");
  if (sheet.getLastRow() === 0) {
    sheet.appendRow(["ID_TRANSACAO", "DATA", "ID_MATERIAL", "MATERIAL", "MOVIMENTACAO", "QUANTIDADE", "OBSERVACAO", "SALDO_FINAL"]);
  }

  sheet.appendRow([
    log.ID_TRANSACAO,
    log.DATA,
    log.ID_MATERIAL,
    log.MATERIAL,
    log.MOVIMENTACAO,
    log.QUANTIDADE,
    log.OBSERVACAO,
    log.SALDO_FINAL
  ]);
}

// 3. Registra log na planilha de PEDIDOS
function registrarPedido(ss, pedido) {
  const sheet = ss.getSheetByName("PEDIDOS") || ss.insertSheet("PEDIDOS");
  if (sheet.getLastRow() === 0) {
    sheet.appendRow(["ID_PEDIDO", "DATA", "VTR", "REGIAO", "SOLICITANTE", "ITENS", "STATUS"]);
  }

  sheet.appendRow([
    pedido.ID_PEDIDO,
    pedido.DATA,
    pedido.VTR,
    pedido.REGIAO,
    pedido.SOLICITANTE,
    pedido.ITENS,
    pedido.STATUS
  ]);
}

// 4. Atualiza apenas o Status na planilha de PEDIDOS
function atualizarStatusPedido(ss, payload) {
  const sheet = ss.getSheetByName("PEDIDOS");
  if (!sheet) return;

  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == payload.ID_PEDIDO) {
      sheet.getRange(i + 1, 7).setValue(payload.STATUS); // Coluna G (Status)
      break;
    }
  }
}
