### Importante: Configuração Sugerida do Google Apps Script
Para que este App grave corretamente, o seu Script no Google deve tratar as requisições assim:

```javascript
function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  var type = data.type;
  var payload = data.payload;

  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
    var sheet = ss.getSheetByName('ESTOQUE');
    sheet.clearContents();
    // Adiciona cabeçalhos
    sheet.appendRow(['ID_MATERIAL', 'MATERIAL', 'SALDO_ITABAIANA', 'SALDO_DORES']);
    // Adiciona itens
    payload.forEach(function(item) {
      sheet.appendRow([item.ID_MATERIAL, item.MATERIAL, item.SALDO_ITABAIANA, item.SALDO_DORES]);
    });
  } else if (type === 'MOVIMENTACAO_ESTOQUE') {
    var sheet = ss.getSheetByName('LOGS');
    sheet.appendRow([payload.DATA, payload.ID_MATERIAL, payload.MATERIAL, payload.MOVIMENTACAO, payload.QUANTIDADE, payload.OBSERVACAO, payload.SALDO_FINAL]);
  }
  // ... outros tipos ...

  return ContentService.createTextOutput(JSON.stringify({status: 'success'}))
    .setMimeType(ContentService.MimeType.JSON);
}
```

**Dica Final:** Se o app ainda não estiver gravando, tente trocar `mode: 'cors'` por `mode: 'no-cors'` na função `syncToGoogleSheets`. Isso "força" o envio, embora você não consiga ler a resposta de erro detalhada no console. Além disso, verifique se as abas da sua planilha se chamam exatamente `ESTOQUE` e `LOGS` (ou conforme o seu script).

Para que o seu aplicativo consiga gravar e ler os dados corretamente, o código no **Google Apps Script** precisa estar perfeitamente alinhado com as chamadas que o frontend faz.

Abaixo está o código completo e otimizado. Ele gerencia três abas: `ESTOQUE` (saldo atual), `LOGS` (histórico de entradas/saídas) e `PEDIDOS` (solicitações das viaturas).

### Instruções de Instalação no Google Sheets:
1. No seu Google Sheets, crie 3 abas com os nomes exatos: `ESTOQUE`, `LOGS` e `PEDIDOS`.
2. Vá em **Extensões** > **Apps Script**.
3. Apague todo o código existente e cole o código abaixo.
4. Clique em **Implantar** > **Nova Implantação**.
5. Selecione **App da Web**.
6. Em "Executar como", selecione **Eu**.
7. Em "Quem pode acessar", selecione **Qualquer pessoa** (Isso é vital para o app funcionar).
8. Copie a **URL do App da Web** gerada e cole no campo "Configuração da Nuvem" no seu App ou no arquivo `constants.ts`.

---

### Código para o Google Apps Script (Code.gs)

```javascript
/**
 * CONFIGURAÇÕES INICIAIS
 * Certifique-se de que as abas se chamam: ESTOQUE, LOGS e PEDIDOS
 */

function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  // Rota de Leitura de Estoque
  if (action === 'read' || !action) {
    var sheet = ss.getSheetByName('ESTOQUE');
    var data = sheet.getDataRange().getValues();
    var headers = data[0];
    var json = [];

    for (var i = 1; i < data.length; i++) {
      var obj = {};
      for (var j = 0; j < headers.length; j++) {
        obj[headers[j]] = data[i][j];
      }
      json.push(obj);
    }

    return ContentService.createTextOutput(JSON.stringify(json))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var result = { status: 'error', message: 'Tipo de operação não reconhecido' };

  try {
    var data = JSON.parse(e.postData.contents);
    var type = data.type;
    var payload = data.payload;

    // 1. ATUALIZAÇÃO TOTAL DO ESTOQUE (Sobrescreve a aba com novos saldos)
    if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = ss.getSheetByName('ESTOQUE');
      sheet.clear(); // Limpa tudo

      // Cabeçalhos padrão
      var headers = ['ID_MATERIAL', 'MATERIAL', 'SALDO_ITABAIANA', 'SALDO_DORES'];
      sheet.appendRow(headers);

      // Insere cada item vindo do App
      if (Array.isArray(payload)) {
        payload.forEach(function(item) {
          sheet.appendRow([
            item.ID_MATERIAL,
            item.MATERIAL,
            item.SALDO_ITABAIANA,
            item.SALDO_DORES
          ]);
        });
      }
      result = { status: 'success' };
    }

    // 2. LOG DE MOVIMENTAÇÃO (Entradas/Saídas Manuais)
    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = ss.getSheetByName('LOGS');
      // Adiciona cabeçalho se a planilha estiver vazia
      if (sheet.getLastRow() === 0) {
        sheet.appendRow(['DATA', 'ID_MATERIAL', 'MATERIAL', 'MOVIMENTACAO', 'QUANTIDADE', 'OBSERVACAO', 'SALDO_FINAL']);
      }

      sheet.appendRow([
        payload.DATA,
        payload.ID_MATERIAL,
        payload.MATERIAL,
        payload.MOVIMENTACAO,
        payload.QUANTIDADE,
        payload.OBSERVACAO,
        payload.SALDO_FINAL || 0
      ]);
      result = { status: 'success' };
    }

    // 3. NOVA SOLICITAÇÃO (Pedidos feitos pelas viaturas)
    else if (type === 'NOVA_SOLICITACAO') {
      var sheet = ss.getSheetByName('PEDIDOS');
      if (sheet.getLastRow() === 0) {
        sheet.appendRow(['ID_PEDIDO', 'DATA', 'VTR', 'REGIAO', 'SOLICITANTE', 'ITENS', 'STATUS']);
      }

      sheet.appendRow([
        payload.ID_PEDIDO,
        payload.DATA,
        payload.VTR,
        payload.REGIAO,
        payload.SOLICITANTE,
        payload.ITENS,
        payload.STATUS
      ]);
      result = { status: 'success' };
    }

    // 4. ATUALIZAÇÃO DE STATUS DO PEDIDO (Atendimento)
    else if (type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName('PEDIDOS');
      var rows = sheet.getDataRange().getValues();
      var idProcurado = payload.ID_PEDIDO;

      for (var i = 1; i < rows.length; i++) {
        if (rows[i][0] == idProcurado) {
          sheet.getRange(i + 1, 7).setValue(payload.STATUS); // Coluna 7 é o Status
          break;
        }
      }
      result = { status: 'success' };
    }

  } catch (err) {
    result = { status: 'error', message: err.toString() };
  }

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### O que mudou e por que isso resolve seu problema:

1.  **Sincronização Bidirecional**: O `doGet` agora responde ao parâmetro `action=read`, permitindo que o App peça os dados sempre que necessário.
2.  **Robustez no `doPost`**: O script agora detecta se o que chegou é um pedido novo, uma alteração de status ou uma atualização de saldo.
3.  **Gestão de Tabelas**: O comando `sheet.clear()` e `sheet.appendRow()` no caso da atualização total garante que a planilha sempre reflita o estado atual do App, sem duplicar linhas ou deixar dados fantasmas.
4.  **Tratamento de CORS**: Ao retornar `ContentService.createTextOutput(JSON.stringify(result))`, o Google envia os headers necessários para que o navegador não bloqueie a resposta, mesmo em requisições de domínios diferentes.

**Dica Extra:** Após colar o código e implantar, se você fizer qualquer mudança no script, você **precisa** clicar em "Gerenciar Implantações" e editar a implantação atual ou criar uma nova versão, senão a URL antiga continuará rodando o código velho.

