### Código do Google Apps Script (Para colar no Script Editor)

Este é o código que deve estar no seu Script do Google para funcionar com as alterações acima:

```javascript
function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'read' || !action) {
    var sheet = ss.getSheetByName('ESTOQUE');
    if(!sheet) return ContentService.createTextOutput("[]").setMimeType(ContentService.MimeType.JSON);
    var data = sheet.getDataRange().getValues();
    var headers = data[0];
    var json = [];

    for (var i = 1; i < data.length; i++) {
      var obj = {};
      for (var j = 0; j < headers.length; j++) {
        obj[headers[j]] = data[i][j];
      }
      json.push(obj);
    }
    return ContentService.createTextOutput(JSON.stringify(json)).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var result = { status: 'error' };

  try {
    var contents = JSON.parse(e.postData.contents);
    var type = contents.type;
    var payload = contents.payload;

    if (type === 'ATUALIZAR_ESTOQUE_TOTAL') {
      var sheet = ss.getSheetByName('ESTOQUE') || ss.insertSheet('ESTOQUE');
      sheet.clear();
      sheet.appendRow(['ID_MATERIAL', 'MATERIAL', 'SALDO_ITABAIANA', 'SALDO_DORES']);
      payload.forEach(function(item) {
        sheet.appendRow([item.ID_MATERIAL, item.MATERIAL, item.SALDO_ITABAIANA, item.SALDO_DORES]);
      });
      result.status = 'success';
    } 
    else if (type === 'MOVIMENTACAO_ESTOQUE') {
      var sheet = ss.getSheetByName('LOGS') || ss.insertSheet('LOGS');
      if (sheet.getLastRow() === 0) sheet.appendRow(['DATA', 'ID_MATERIAL', 'MATERIAL', 'MOVIMENTACAO', 'QUANTIDADE', 'OBSERVACAO', 'SALDO_FINAL']);
      sheet.appendRow([payload.DATA, payload.ID_MATERIAL, payload.MATERIAL, payload.MOVIMENTACAO, payload.QUANTIDADE, payload.OBSERVACAO, payload.SALDO_FINAL]);
      result.status = 'success';
    }
    else if (type === 'NOVA_SOLICITACAO') {
      var sheet = ss.getSheetByName('PEDIDOS') || ss.insertSheet('PEDIDOS');
      if (sheet.getLastRow() === 0) sheet.appendRow(['ID_PEDIDO', 'DATA', 'VTR', 'REGIAO', 'SOLICITANTE', 'ITENS', 'STATUS']);
      sheet.appendRow([payload.ID_PEDIDO, payload.DATA, payload.VTR, payload.REGIAO, payload.SOLICITANTE, payload.ITENS, payload.STATUS]);
      result.status = 'success';
    }
    else if (type === 'ATUALIZACAO_STATUS_PEDIDO') {
      var sheet = ss.getSheetByName('PEDIDOS');
      var rows = sheet.getDataRange().getValues();
      for (var i = 1; i < rows.length; i++) {
        if (rows[i][0] == payload.ID_PEDIDO) {
          sheet.getRange(i + 1, 7).setValue(payload.STATUS);
          break;
        }
      }
      result.status = 'success';
    }
  } catch (err) {
    result.error = err.toString();
  }

  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}
```

**Lembre-se:** Sempre que alterar o código no Google Script, clique em **Implantar > Gerenciar Implantações > Editar (lápis) > Nova Versão > Implantar**. Use sempre a URL da **versão mais recente**.

Para que os pedidos e o estoque sejam visíveis em qualquer dispositivo (celular, computador, etc.), o aplicativo não pode depender do `localStorage` (armazenamento local do navegador) como fonte da verdade. Ele deve **buscar e enviar tudo para a nuvem (Google Sheets)**.

