      status: (String(item.STATUS).toLowerCase().includes('atendido') ? 'served' : 'pending') as 'served' | 'pending',
      timestamp: item.DATA ? new Date(item.DATA).getTime() : Date.now(),
      items: parsedItems
    } as MaterialRequest;
  }).filter(r => r.id);
};

